export const UFPR_GERADO_2026_QUESTIONS: any[] = [
  { id: 'ufpr_gerado26_001', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Na resposta metabólica ao trauma, a fase de refluxo (ebb phase), que ocorre nas primeiras horas após a agressão, é caracterizada principalmente por:', options: ['hipometabolismo, vasoconstrição periférica e redução do débito cardíaco.', 'hipermetabolismo intenso com aumento do gasto energético basal.', 'balanço nitrogenado positivo, com síntese proteica predominante.', 'hiperglicemia por aumento isolado da secreção de insulina.', 'hipertermia sustentada como achado predominante e constante.'], correctIndex: 0, explanation: 'A fase de refluxo (ebb phase) é caracterizada por hipometabolismo, vasoconstrição periférica e redução do débito cardíaco, representando resposta inicial de preservação de volume circulante. O hipermetabolismo é característico da fase de fluxo (flow phase), subsequente; o balanço nitrogenado é negativo (catabolismo proteico), não positivo; a hiperglicemia do trauma decorre de resistência insulínica e hormônios contrarreguladores, não de aumento isolado de insulina; a hipertermia não é achado constante dessa fase inicial, marcada por hipotermia relativa.' },
  { id: 'ufpr_gerado26_002', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Citocina fundamental na fase inflamatória da cicatrização de feridas, produzida por macrófagos, com papel quimiotático para neutrófilos e estímulo à angiogênese, é:', options: ['fator de necrose tumoral alfa (TNF-alfa).', 'eritropoetina.', 'hormônio do crescimento.', 'insulina.', 'paratormônio.'], correctIndex: 0, explanation: 'O TNF-alfa, produzido por macrófagos na fase inflamatória, tem papel quimiotático para neutrófilos e estimula a angiogênese, sendo central no processo de cicatrização. Eritropoetina atua na eritropoiese, sem esse papel cicatricial; hormônio do crescimento tem ação sistêmica sobre crescimento tecidual, não é a citocina-chave dessa fase; insulina regula metabolismo glicídico, sem esse papel quimiotático específico; paratormônio regula o metabolismo do cálcio, sem relação direta com a cicatrização.' },
  { id: 'ufpr_gerado26_003', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Paciente, 45 anos, será submetido a laparotomia eletiva para ressecção de neoplasia colônica, sem desnutrição prévia significativa. Segundo as diretrizes atuais de nutrição perioperatória, é correto afirmar que:', options: ['o jejum pré-operatório prolongado tradicional foi substituído por protocolos que permitem ingestão de líquidos claros até poucas horas antes da cirurgia.', 'a nutrição parenteral total deve ser iniciada rotineiramente no pré-operatório de todos os pacientes, independente do estado nutricional.', 'o jejum de 12 horas para sólidos e líquidos, sem exceção, ainda é a única recomendação vigente.', 'a dieta oral só pode ser reiniciada após confirmação radiológica de trânsito intestinal normal no pós-operatório.', 'a suplementação nutricional pré-operatória é contraindicada em pacientes sem desnutrição.'], correctIndex: 0, explanation: 'Os protocolos atuais (como ERAS) permitem ingestão de líquidos claros até poucas horas antes da cirurgia, abandonando o jejum prolongado tradicional. Nutrição parenteral total rotineira não é indicada em pacientes sem desnutrição significativa; o jejum de 12h para líquidos claros não é mais a recomendação vigente; a dieta oral pode ser reiniciada precocemente no pós-operatório sem necessidade de confirmação radiológica de trânsito em cirurgias eletivas não complicadas; a suplementação nutricional pré-operatória pode ser considerada mesmo sem desnutrição estabelecida, conforme risco cirúrgico.' },
  { id: 'ufpr_gerado26_004', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Homem, 68 anos, tabagista, com claudicação intermitente progressiva em membro inferior direito, pulsos femorais diminuídos e ausência de pulsos distais. A condição clínica mais frequentemente relacionada à oclusão arterial crônica progressiva dos membros nesse perfil de paciente é:', options: ['doença arterial obstrutiva periférica aterosclerótica.', 'trombose venosa profunda.', 'síndrome compartimental aguda.', 'embolia gordurosa.', 'flebite superficial.'], correctIndex: 0, explanation: 'Claudicação progressiva com pulsos diminuídos em tabagista é o quadro clássico da doença arterial obstrutiva periférica de etiologia aterosclerótica. Trombose venosa profunda cursa com edema e dor, não claudicação com pulsos reduzidos; síndrome compartimental é quadro agudo, não progressivo crônico; embolia gordurosa está associada a fraturas de ossos longos, com quadro sistêmico agudo; flebite superficial não causa claudicação nem redução de pulsos arteriais.' },
  { id: 'ufpr_gerado26_005', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'O pneumotórax espontâneo primário, em comparação ao secundário, é caracterizado por:', options: ['ocorrer em indivíduos sem doença pulmonar estrutural subjacente conhecida, geralmente jovens e longilíneos.', 'ocorrer exclusivamente em pacientes com DPOC avançada.', 'apresentar maior mortalidade do que o pneumotórax secundário em todas as faixas etárias.', 'ser sempre indicação obrigatória de pleurodese cirúrgica no primeiro episódio.', 'não ter qualquer relação com a ruptura de bolhas subpleurais (blebs).'], correctIndex: 0, explanation: 'O pneumotórax espontâneo primário ocorre em indivíduos sem doença pulmonar estrutural subjacente conhecida, tipicamente jovens e longilíneos, por ruptura de bolhas subpleurais. Ocorrer exclusivamente em DPOC descreve o secundário, não o primário; o primário geralmente tem menor mortalidade que o secundário, que ocorre em pulmões já comprometidos; a pleurodese não é obrigatória no primeiro episódio, sendo reservada a recidivas ou situações específicas; a ruptura de blebs subpleurais é justamente o mecanismo mais associado ao pneumotórax primário.' },
  { id: 'ufpr_gerado26_006', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Mulher, 55 anos, portadora de colelitíase sintomática, com indicação de colecistectomia videolaparoscópica eletiva. Além da avaliação clínica pré-operatória habitual, um cuidado específico relacionado à técnica cirúrgica é:', options: ['identificação segura do triângulo de Calot antes da ligadura do ducto e da artéria císticos, para reduzir risco de lesão de via biliar principal.', 'ligadura obrigatória do ducto hepático comum antes de qualquer dissecção do triângulo de Calot.', 'dispensa de qualquer identificação anatômica quando a cirurgia é realizada por via laparoscópica.', 'necessidade obrigatória de colangiografia intraoperatória em todos os casos, sem exceção.', 'contraindicação absoluta da via laparoscópica em mulheres acima de 50 anos.'], correctIndex: 0, explanation: 'A identificação segura do triângulo de Calot antes da ligadura do ducto e artéria císticos é medida central para evitar lesão iatrogênica da via biliar principal, complicação grave da colecistectomia. Ligar o ducto hepático comum seria um erro grave, não um cuidado de segurança; a identificação anatômica cuidadosa é ainda mais importante na via laparoscópica, não dispensável; colangiografia intraoperatória é indicada seletivamente, não obrigatória em todos os casos; não há contraindicação da via laparoscópica por faixa etária isoladamente.' },
  { id: 'ufpr_gerado26_007', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Em relação à classificação de contaminação das feridas cirúrgicas, uma apendicectomia por apendicite aguda não perfurada, sem extravasamento de conteúdo purulento na cavidade, é classificada como ferida:', options: ['potencialmente contaminada.', 'limpa.', 'contaminada.', 'infectada.', 'asséptica, sem qualquer risco de infecção de sítio cirúrgico.'], correctIndex: 0, explanation: 'A abertura de uma víscera oca inflamada, sem extravasamento franco de conteúdo purulento, classifica a ferida como potencialmente contaminada. Classificá-la como limpa ignora a abertura de víscera oca inflamada; contaminada exigiria extravasamento franco de conteúdo entérico ou quebra maior de técnica asséptica; infectada exigiria processo infeccioso já estabelecido no sítio operatório, como abscesso já formado na ferida; nenhuma ferida com abertura de víscera é considerada asséptica e livre de qualquer risco de infecção.' },
  { id: 'ufpr_gerado26_008', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Em relação à resposta inflamatória sistêmica à agressão cirúrgica, o cortisol liberado durante o estresse cirúrgico tem, entre outros, o seguinte efeito metabólico:', options: ['estímulo à gliconeogênese hepática, contribuindo para a hiperglicemia do estresse cirúrgico.', 'inibição completa da gliconeogênese hepática.', 'estímulo isolado à síntese proteica muscular, sem qualquer efeito catabólico.', 'supressão completa da liberação de catecolaminas.', 'redução da glicemia por aumento da sensibilidade periférica à insulina.'], correctIndex: 0, explanation: 'O cortisol estimula a gliconeogênese hepática, contribuindo para a hiperglicemia observada na resposta ao estresse cirúrgico. Inibir a gliconeogênese seria efeito oposto ao real; o cortisol tem efeito catabólico proteico muscular, não estímulo isolado à síntese sem efeito catabólico; o cortisol não suprime catecolaminas, atuando de forma sinérgica com elas na resposta ao estresse; o cortisol reduz, não aumenta, a sensibilidade periférica à insulina, contribuindo para a hiperglicemia, não para redução da glicemia.' },
  { id: 'ufpr_gerado26_009', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Homem, 30 anos, vítima de ferimento penetrante abdominal por arma de fogo, instável hemodinamicamente. A conduta padrão nesse contexto, segundo os princípios de cirurgia de controle de danos, prioriza:', options: ['controle rápido de hemorragia e contaminação, adiando reconstruções definitivas para momento posterior, após estabilização fisiológica.', 'reconstrução anatômica completa e definitiva de todas as lesões na primeira intervenção, independente do tempo cirúrgico necessário.', 'observação clínica isolada, sem intervenção cirúrgica imediata, independente da instabilidade.', 'anastomoses intestinais múltiplas complexas como prioridade sobre o controle hemorrágico.', 'fechamento definitivo da parede abdominal como prioridade sobre o controle da hemorragia.'], correctIndex: 0, explanation: 'A cirurgia de controle de danos prioriza o controle rápido de hemorragia e contaminação, adiando reconstruções definitivas para depois da estabilização fisiológica do paciente instável. Reconstrução completa na primeira intervenção prolonga o tempo cirúrgico e agrava a tríade letal (hipotermia, acidose, coagulopatia); observação isolada é inadequada diante de instabilidade e ferimento penetrante; anastomoses complexas antes do controle hemorrágico invertem a prioridade correta; fechamento definitivo da parede antes do controle da hemorragia também inverte essa prioridade.' },
  { id: 'ufpr_gerado26_010', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Mulher, 62 anos, com massa palpável em quadrante superior externo da mama direita, mamografia com lesão espiculada BI-RADS 5. O próximo passo mais adequado antes de definir a estratégia terapêutica é:', options: ['biópsia percutânea (core biopsy) para confirmação histológica.', 'mastectomia radical imediata, sem confirmação histológica prévia.', 'observação clínica com nova mamografia em 12 meses.', 'quimioterapia empírica, sem qualquer biópsia.', 'radioterapia isolada, sem diagnóstico histológico prévio.'], correctIndex: 0, explanation: 'Mesmo com alta suspeição radiológica (BI-RADS 5), a biópsia percutânea é necessária para confirmação histológica antes de definir a estratégia terapêutica. Mastectomia sem confirmação histológica submeteria a paciente a cirurgia mutiladora sem diagnóstico definitivo; observação por 12 meses é inadequada diante de lesão de alta suspeição; quimioterapia e radioterapia empíricas sem biópsia tratariam uma doença ainda não confirmada histologicamente.' },
  { id: 'ufpr_gerado26_011', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Em relação ao manejo da apendicite aguda não complicada em adultos, é correto afirmar que:', options: ['a apendicectomia (aberta ou laparoscópica) permanece o tratamento padrão-ouro, embora o tratamento antibiótico isolado seja opção em casos selecionados.', 'o tratamento antibiótico isolado substitui completamente a necessidade de cirurgia em todos os casos.', 'a apendicectomia deve ser postergada por, no mínimo, 72 horas em todos os casos não complicados.', 'a via laparoscópica é formalmente contraindicada na apendicite aguda.', 'não há qualquer papel do exame de imagem na investigação diagnóstica da apendicite aguda.'], correctIndex: 0, explanation: 'A apendicectomia permanece o tratamento padrão-ouro da apendicite aguda não complicada, ainda que o tratamento antibiótico isolado seja opção em casos selecionados, conforme evidências mais recentes. Afirmar que o antibiótico substitui completamente a cirurgia em todos os casos é excessivo, pois a apendicectomia continua o padrão-ouro; postergar a cirurgia por 72 horas não é recomendação padrão em casos não complicados; a via laparoscópica é amplamente utilizada e não contraindicada; exames de imagem (ultrassom, tomografia) têm papel relevante na investigação diagnóstica, especialmente em casos duvidosos.' },
  { id: 'ufpr_gerado26_012', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Homem, 50 anos, com pancreatite aguda grave, evolui no quarto dia de internação com necrose pancreática identificada em tomografia, sem sinais clínicos ou laboratoriais de infecção. A conduta mais apropriada nesse momento é:', options: ['manejo conservador com suporte clínico, sem indicação de intervenção sobre a necrose estéril.', 'necrosectomia cirúrgica imediata, independente de sinais de infecção.', 'antibioticoterapia profilática de rotina para necrose estéril.', 'drenagem percutânea imediata, independente de sinais de infecção.', 'CPRE de urgência, independente de obstrução biliar concomitante.'], correctIndex: 0, explanation: 'Necrose pancreática estéril, sem sinais de infecção, é manejada de forma conservadora, reservando intervenção (drenagem ou necrosectomia) para necrose infectada ou complicações. Necrosectomia imediata sem sinais de infecção é conduta desproporcional e associada a maior morbimortalidade; antibioticoterapia profilática de rotina para necrose estéril não é recomendada pelas diretrizes atuais; drenagem percutânea imediata sem sinais de infecção não é indicada; CPRE de urgência é reservada a casos com obstrução biliar concomitante, não de rotina em toda pancreatite necrosante.' },
  { id: 'ufpr_gerado26_013', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Em relação ao trauma torácico fechado, o pneumotórax hipertensivo é caracterizado por:', options: ['acúmulo progressivo de ar no espaço pleural com mecanismo valvular, causando desvio contralateral do mediastino e comprometimento hemodinâmico.', 'ser diagnóstico exclusivamente radiológico, nunca clínico.', 'não causar qualquer repercussão hemodinâmica, apenas respiratória.', 'exigir sempre toracotomia como tratamento inicial, nunca descompressão com agulha.', 'ser tratado preferencialmente com observação clínica isolada, sem descompressão.'], correctIndex: 0, explanation: 'O pneumotórax hipertensivo é caracterizado por acúmulo progressivo de ar por mecanismo valvular, causando desvio contralateral do mediastino e comprometimento hemodinâmico grave. É diagnóstico eminentemente clínico, devendo ser tratado sem aguardar confirmação radiológica; causa sim repercussão hemodinâmica significativa, não apenas respiratória; o tratamento inicial é a descompressão com agulha (ou dedo), não toracotomia; observação isolada é perigosa e contraindicada diante desse quadro de risco iminente de morte.' },
  { id: 'ufpr_gerado26_014', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Homem, 60 anos, com massa abdominal pulsátil identificada em exame de rotina, ultrassonografia confirmando aneurisma de aorta abdominal infrarrenal de 5,7 cm, assintomático. A conduta mais apropriada é:', options: ['correção cirúrgica eletiva (aberta ou endovascular), pelo tamanho acima do limiar de tratamento.', 'acompanhamento seriado anual, sem intervenção, independente do tamanho.', 'anticoagulação plena isolada, sem qualquer intervenção sobre o aneurisma.', 'embolização isolada sem exclusão completa do saco aneurismático.', 'observação clínica exclusiva até que o paciente se torne sintomático.'], correctIndex: 0, explanation: 'Aneurisma de aorta abdominal acima de 5,5 cm tem indicação de correção eletiva pelo risco progressivo de rotura, independentemente de sintomas. Acompanhamento seriado é apropriado para aneurismas menores, abaixo do limiar cirúrgico; anticoagulação plena não trata o risco de rotura; embolização isolada sem exclusão completa não elimina o risco; aguardar até que se torne sintomático é perigoso, pois sintomas podem indicar rotura iminente ou já estabelecida.' },
  { id: 'ufpr_gerado26_015', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Em relação à classificação das queimaduras, a queimadura de espessura total (terceiro grau) é caracterizada por:', options: ['destruição de epiderme e derme completas, com aspecto esbranquiçado ou carbonizado e ausência de dor pela destruição de terminações nervosas locais.', 'acometimento superficial limitado à epiderme, com hiperemia e dor intensa.', 'formação de flictenas (bolhas) como achado predominante e específico.', 'ser sempre indolor devido à preservação completa da inervação cutânea.', 'não necessitar de qualquer intervenção cirúrgica em nenhuma circunstância.'], correctIndex: 0, explanation: 'A queimadura de terceiro grau destrói epiderme e derme completas, apresentando aspecto esbranquiçado ou carbonizado e sendo tipicamente indolor pela destruição das terminações nervosas. Acometimento superficial com hiperemia e dor intensa descreve queimadura de primeiro grau; flictenas são características de queimaduras de segundo grau superficial; a ausência de dor decorre da destruição da inervação, não de sua preservação; queimaduras extensas de terceiro grau frequentemente necessitam de enxertia cutânea, não sendo correto afirmar ausência total de indicação cirúrgica.' },
  { id: 'ufpr_gerado26_016', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Homem, 55 anos, com massa cervical anterior de crescimento progressivo, ultrassonografia de tireoide classificando o nódulo como alto risco (TI-RADS 5). A próxima etapa de investigação mais apropriada é:', options: ['punção aspirativa por agulha fina do nódulo, guiada por ultrassonografia.', 'tireoidectomia total imediata, sem qualquer confirmação citológica prévia.', 'observação clínica isolada, sem qualquer investigação adicional.', 'radioterapia isolada, sem avaliação cirúrgica ou citológica prévia.', 'cintilografia como único exame necessário, sem punção.'], correctIndex: 0, explanation: 'Nódulo de alto risco ultrassonográfico tem indicação de punção aspirativa por agulha fina guiada por imagem para definir a conduta subsequente. Tireoidectomia sem confirmação citológica prévia é desproporcional sem diagnóstico; observação isolada ignora as características de alto risco; radioterapia isolada não é conduta inicial apropriada; cintilografia é mais útil em nódulos hiperfuncionantes com TSH suprimido, não substituindo a punção nesse contexto de alto risco ultrassonográfico.' },
  { id: 'ufpr_gerado26_017', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Em relação à isquemia mesentérica aguda, é correto afirmar que:', options: ['a dor abdominal desproporcional aos achados do exame físico é achado clássico nas fases iniciais.', 'o diagnóstico é habitualmente tardio devido à ausência completa de sintomas em qualquer fase da doença.', 'a etiologia embólica é rara, sendo a causa predominante sempre trombótica venosa.', 'o tratamento é sempre exclusivamente clínico, sem qualquer papel para intervenção cirúrgica ou endovascular.', 'não há qualquer relação entre isquemia mesentérica e fibrilação atrial.'], correctIndex: 0, explanation: 'A dor abdominal desproporcional aos achados do exame físico é achado clássico da isquemia mesentérica aguda em fase inicial, antes da necrose transmural estabelecida. A doença não é assintomática, mas seu diagnóstico pode ser tardio justamente pela discrepância entre sintomas e exame físico, levando a subestimação inicial; a etiologia embólica (frequentemente por fibrilação atrial) é causa importante, não rara; o tratamento pode exigir intervenção cirúrgica ou endovascular de urgência, não sendo exclusivamente clínico; a fibrilação atrial é justamente fator de risco relevante para embolia mesentérica.' },
  { id: 'ufpr_gerado26_018', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'Mulher, 28 anos, com dismenorreia progressiva, dispareunia de profundidade e infertilidade, ressonância magnética sugerindo endometrioma ovariano. O diagnóstico mais provável é:', options: ['endometriose.', 'miomatose uterina.', 'doença inflamatória pélvica aguda.', 'câncer epitelial de ovário.', 'adenomiose isolada, sem acometimento ovariano.'], correctIndex: 0, explanation: 'Dismenorreia progressiva, dispareunia de profundidade, infertilidade e endometrioma ovariano são compatíveis com endometriose. Miomatose uterina cursa com sangramento aumentado e miomas uterinos, não endometrioma; doença inflamatória pélvica aguda cursa com quadro infeccioso agudo, não endometrioma crônico; câncer epitelial de ovário teria características de imagem distintas e mais preocupantes; adenomiose acomete o miométrio, não formando endometrioma ovariano.' },
  { id: 'ufpr_gerado26_019', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'Em relação à síndrome dos ovários policísticos, os critérios de Rotterdam exigem, para o diagnóstico, pelo menos dois dos seguintes três critérios:', options: ['oligo/anovulação, hiperandrogenismo clínico ou laboratorial, e morfologia ovariana policística à ultrassonografia.', 'amenorreia primária, galactorreia e hipotireoidismo confirmado.', 'obesidade grau III, diabetes tipo 1 e hipertensão arterial secundária.', 'menarca precoce, ciclos regulares e ausência completa de hirsutismo.', 'FSH e LH ambos suprimidos, com estradiol muito elevado.'], correctIndex: 0, explanation: 'Os critérios de Rotterdam exigem pelo menos dois entre oligo/anovulação, hiperandrogenismo (clínico ou laboratorial) e morfologia ovariana policística. Amenorreia primária com galactorreia e hipotireoidismo sugere outra etiologia (hiperprolactinemia), não os critérios de SOP; obesidade grau III com diabetes tipo 1 não são critérios diagnósticos de Rotterdam; ciclos regulares sem hirsutismo não caracterizam SOP; o perfil hormonal com FSH/LH suprimidos e estradiol elevado não é o padrão típico da SOP.' },
  { id: 'ufpr_gerado26_020', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'Mulher, 60 anos, menopausada, com sangramento vaginal e ultrassom evidenciando espessamento endometrial de 12 mm. A conduta diagnóstica mais apropriada é:', options: ['biópsia endometrial (por curetagem, histeroscopia ou outro método adequado).', 'observação clínica isolada, sem investigação adicional.', 'histerectomia imediata, sem biópsia prévia.', 'terapia hormonal isolada, sem investigação da causa do sangramento.', 'colposcopia isolada, sem avaliação endometrial.'], correctIndex: 0, explanation: 'Sangramento pós-menopausa com espessamento endometrial exige biópsia para investigação histológica, excluindo hiperplasia atípica ou câncer de endométrio. Observação isolada atrasa perigosamente o diagnóstico de uma possível neoplasia; histerectomia sem biópsia prévia é desproporcional sem diagnóstico histológico; terapia hormonal isolada não investiga a causa nem exclui malignidade; colposcopia avalia o colo uterino, não o endométrio, sendo exame inadequado para essa investigação específica.' },
  { id: 'ufpr_gerado26_021', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'Adolescente de 16 anos, com menarca há 3 anos, ciclos irregulares, hirsutismo progressivo e acne importante. Investigação laboratorial deve incluir, entre outros, a dosagem de:', options: ['testosterona total e livre, para investigação de hiperandrogenismo.', 'apenas hemograma completo, sem qualquer avaliação hormonal.', 'apenas glicemia de jejum isolada, sem avaliação androgênica.', 'cálcio e fósforo séricos, sem qualquer relação com o quadro descrito.', 'apenas colesterol total, sem avaliação hormonal androgênica.'], correctIndex: 0, explanation: 'Hirsutismo progressivo e acne em adolescente com ciclos irregulares sugerem hiperandrogenismo, exigindo dosagem de testosterona total e livre na investigação. Hemograma isolado não avalia o eixo hormonal relevante ao quadro; glicemia isolada não investiga a causa do hiperandrogenismo, embora possa ser complementar; cálcio e fósforo não têm relação direta com esse quadro clínico; colesterol total isolado não substitui a avaliação hormonal androgênica necessária.' },
  { id: 'ufpr_gerado26_022', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'Mulher, 32 anos, sexualmente ativa, com dor pélvica, febre e corrimento cervical purulento, dor à mobilização do colo uterino ao exame especular. A conduta mais apropriada é:', options: ['iniciar antibioticoterapia empírica de amplo espectro para doença inflamatória pélvica, cobrindo gonococo e clamídia.', 'aguardar resultado de cultura antes de iniciar qualquer tratamento.', 'indicar laparotomia exploradora imediata, independente da gravidade.', 'tranquilizar a paciente, pois o quadro é autolimitado e não exige tratamento.', 'iniciar apenas analgésico, sem qualquer antibioticoterapia.'], correctIndex: 0, explanation: 'A suspeita clínica de doença inflamatória pélvica justifica início empírico imediato de antibioticoterapia cobrindo gonococo e clamídia, sem necessidade de aguardar cultura, reduzindo o risco de sequelas como infertilidade. Aguardar cultura atrasa o tratamento; laparotomia é reservada a complicações como abscesso tubo-ovariano roto; o quadro não é autolimitado e exige tratamento para evitar sequelas; analgésico isolado não trata a infecção subjacente.' },
  { id: 'ufpr_gerado26_023', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'Segundo as diretrizes brasileiras de rastreamento do câncer do colo do útero, o método de rastreamento primário recomendado e o intervalo padrão são:', options: ['citologia oncótica, com intervalo trienal após dois exames anuais consecutivos normais, a partir dos 25 anos.', 'ressonância magnética pélvica anual, a partir dos 18 anos.', 'tomografia computadorizada de pelve, a cada 5 anos, a partir dos 30 anos.', 'dosagem sérica de CA-125, anualmente, a partir da menarca.', 'ultrassonografia transvaginal isolada, semestralmente, em qualquer idade.'], correctIndex: 0, explanation: 'O rastreamento citológico brasileiro recomenda início aos 25 anos, com periodicidade trienal após dois exames anuais consecutivos normais. Ressonância magnética não é o método de rastreamento primário recomendado; tomografia computadorizada também não é método de rastreio populacional para essa neoplasia; CA-125 não é marcador de rastreamento para câncer de colo uterino; ultrassonografia transvaginal isolada não substitui a citologia como método de rastreio primário dessa neoplasia.' },
  { id: 'ufpr_gerado26_024', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'Mulher, 45 anos, com sangramento uterino aumentado e prolongado, ultrassom evidenciando múltiplos miomas intramurais, sem desejo reprodutivo. Uma opção de tratamento clínico, antes de considerar cirurgia, é:', options: ['dispositivo intrauterino liberador de levonorgestrel.', 'histerectomia como única opção terapêutica disponível.', 'embolização das artérias uterinas como primeira opção obrigatória, sem tentativa clínica prévia.', 'ácido tranexâmico contraindicado nesse contexto de sangramento aumentado.', 'observação isolada, sem qualquer tratamento, independente da intensidade do sangramento.'], correctIndex: 0, explanation: 'O DIU de levonorgestrel é opção clínica eficaz para reduzir o sangramento em mulheres com miomas sem desejo reprodutivo, antes de considerar cirurgia. Histerectomia não é a única opção, havendo alternativas conservadoras; embolização não precisa ser a primeira opção obrigatória antes de tentativa clínica; ácido tranexâmico é opção terapêutica reconhecida, não contraindicada nesse contexto; observação isolada não é apropriada diante de sangramento aumentado sintomático.' },
  { id: 'ufpr_gerado26_025', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'Em relação à contracepção hormonal combinada, o tabagismo em mulheres acima de 35 anos representa:', options: ['contraindicação ao uso, pelo risco cardiovascular aumentado.', 'indicação preferencial, pois reduz o risco tromboembólico associado ao estrogênio.', 'situação irrelevante para a escolha do método contraceptivo.', 'indicação exclusiva de contraceptivos combinados de alta dosagem estrogênica.', 'contraindicação apenas ao método injetável, mas não à pílula combinada oral.'], correctIndex: 0, explanation: 'O tabagismo após os 35 anos é contraindicação reconhecida ao contraceptivo hormonal combinado pelo risco cardiovascular aumentado com o uso concomitante de estrogênio. Afirmar que reduz o risco tromboembólico é o oposto do que ocorre; a situação é altamente relevante para a escolha do método, não irrelevante; não há indicação de doses estrogênicas mais altas nesse contexto, ao contrário, deve-se evitar o método combinado; a contraindicação se aplica ao método combinado de forma geral (oral, injetável, transdérmico, anel), não apenas ao injetável.' },
  { id: 'ufpr_gerado26_026', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'Mulher, 25 anos, com corrimento vaginal amarelo-esverdeado, prurido intenso e colo uterino com aspecto de "morango" ao exame especular. O agente etiológico mais provável e a conduta são, respectivamente:', options: ['Trichomonas vaginalis; metronidazol para a paciente e o(s) parceiro(s) sexual(is).', 'Candida albicans; antifúngico tópico isolado, sem tratamento do parceiro.', 'Gardnerella vaginalis; metronidazol, sem necessidade de tratar o parceiro.', 'Chlamydia trachomatis; azitromicina isolada, sem relação com o achado de colo em "morango".', 'Vírus do papiloma humano; apenas seguimento citológico, sem tratamento medicamentoso.'], correctIndex: 0, explanation: 'O colo em aspecto de "morango" (colpite macular) associado a corrimento e prurido é achado clássico de tricomoníase, tratada com metronidazol, com necessidade de tratar também o parceiro sexual (IST). Candida causa corrimento em grumos sem esse aspecto de colo; Gardnerella (vaginose bacteriana) não costuma causar prurido intenso nem esse aspecto de colo; clamídia não é a etiologia mais associada a esse achado específico do colo; HPV não causa corrimento nem prurido dessa forma, sendo diagnóstico diferente.' },
  { id: 'ufpr_gerado26_027', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'Em relação ao climatério, o primeiro sinal de alteração menstrual que costuma sinalizar o início da transição menopausal é:', options: ['encurtamento do período entre os ciclos menstruais.', 'aumento importante e imediato do fluxo menstrual em todos os ciclos.', 'amenorreia súbita e definitiva, sem qualquer alteração prévia.', 'atrasos menstruais isolados, sem qualquer outra alteração do ciclo.', 'menorragia isolada como primeiro e único sinal da transição.'], correctIndex: 0, explanation: 'O encurtamento do intervalo entre os ciclos menstruais é frequentemente o primeiro sinal da transição menopausal, refletindo encurtamento da fase folicular. Aumento imediato e importante do fluxo não é o sinal mais precoce e característico; a amenorreia definitiva ocorre mais tardiamente no processo, não sendo o primeiro sinal; atrasos menstruais isolados tendem a surgir em fase mais avançada da transição, não como primeiro sinal; menorragia isolada não é descrita como o sinal mais precoce e característico dessa transição.' },
  { id: 'ufpr_gerado26_028', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'Mulher, 30 anos, nuligesta, com prolapso genital leve, sintomática (sensação de peso vaginal), sem desejo reprodutivo imediato. A conduta inicial mais apropriada é:', options: ['fisioterapia do assoalho pélvico, como primeira linha em prolapsos leves e sintomáticos.', 'histerectomia imediata, independente do grau do prolapso.', 'pessário vaginal como única opção terapêutica disponível, sem outras alternativas.', 'cirurgia de correção do prolapso como única conduta possível para qualquer grau.', 'observação isolada, sem qualquer orientação ou intervenção, independente dos sintomas.'], correctIndex: 0, explanation: 'A fisioterapia do assoalho pélvico é indicada como primeira linha em prolapsos leves e sintomáticos, antes de considerar intervenções mais invasivas. Histerectomia imediata é desproporcional para prolapso leve; o pessário não é a única opção, havendo também a fisioterapia e a cirurgia conforme evolução; a cirurgia não é a única conduta possível para qualquer grau, existindo opções conservadoras eficazes; observação isolada sem qualquer orientação ignora os sintomas relatados pela paciente.' },
  { id: 'ufpr_gerado26_029', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Obstetrícia', text: 'Gestante, 34 semanas, com PA 165/105 mmHg, cefaleia e escotomas visuais. A conduta imediata é:', options: ['sulfato de magnésio e avaliação para resolução da gestação.', 'repouso domiciliar, sem qualquer medicação.', 'anti-hipertensivo oral ambulatorial isolado.', 'aguardar 48 horas antes de qualquer conduta.', 'apenas analgésico comum para a cefaleia, sem outra intervenção.'], correctIndex: 0, explanation: 'PA muito elevada com sintomas premonitórios caracteriza pré-eclâmpsia grave, exigindo sulfato de magnésio e avaliação para resolução da gestação. Repouso domiciliar sem medicação não trata a gravidade do quadro; anti-hipertensivo oral ambulatorial isolado é insuficiente diante de sinais premonitórios de eclâmpsia; aguardar 48 horas atrasa perigosamente uma emergência obstétrica; analgésico comum isolado não trata a causa hipertensiva do quadro.' },
  { id: 'ufpr_gerado26_030', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Obstetrícia', text: 'Gestante, 32 semanas, hipertensa, com dor abdominal súbita, hipertonia uterina, sangramento vaginal escuro e sofrimento fetal agudo. O diagnóstico e a conduta são:', options: ['descolamento prematuro de placenta; interrupção imediata da gestação.', 'placenta prévia; conduta expectante.', 'rotura uterina espontânea; observação clínica.', 'trabalho de parto normal; acompanhamento sem intervenção.', 'corioamnionite; apenas antibioticoterapia, sem resolução da gestação.'], correctIndex: 0, explanation: 'Dor súbita, hipertonia uterina e sofrimento fetal em gestante hipertensa são clássicos de descolamento prematuro de placenta, exigindo interrupção imediata. Placenta prévia cursa com sangramento indolor sem hipertonia, padrão oposto; rotura uterina espontânea é rara sem cicatriz uterina prévia; trabalho de parto normal não cursa com sofrimento fetal agudo associado a hipertonia; corioamnionite cursaria com febre materna, não sendo o quadro mais compatível descrito.' },
  { id: 'ufpr_gerado26_031', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Obstetrícia', text: 'Puérpera imediata, com sangramento vaginal importante e útero hipotônico à palpação. A primeira conduta é:', options: ['massagem uterina bimanual e ocitocina.', 'histerectomia imediata.', 'apenas observação.', 'curetagem imediata, sem avaliar o tônus uterino.', 'ácido tranexâmico isolado, sem qualquer manobra sobre o útero.'], correctIndex: 0, explanation: 'Atonia uterina, causa mais comum de hemorragia pós-parto, é tratada inicialmente com massagem bimanual e ocitocina. Histerectomia imediata é medida de exceção para casos refratários; observação isolada é perigosa diante de sangramento ativo; curetagem sem avaliar o tônus ignora a causa mais provável antes de considerar outras etiologias; ácido tranexâmico pode ser associado, mas não substitui a massagem e o uterotônico como primeira conduta diante de atonia.' },
  { id: 'ufpr_gerado26_032', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Obstetrícia', text: 'Gestante Rh negativo, parceiro Rh positivo, 28 semanas, Coombs indireto negativo. A conduta profilática é:', options: ['imunoglobulina anti-D profilática.', 'nenhuma conduta específica.', 'transfusão intrauterina profilática.', 'interrupção antecipada da gestação.', 'dopplervelocimetria de artéria cerebral média isolada, sem qualquer profilaxia medicamentosa.'], correctIndex: 0, explanation: 'Gestante Rh negativo não sensibilizada deve receber imunoglobulina anti-D por volta da 28ª semana para prevenir aloimunização. Não realizar conduta específica expõe ao risco de sensibilização futura; transfusão intrauterina é tratamento de anemia fetal grave já estabelecida, não profilaxia; interrupção antecipada não tem indicação nessa situação de rotina; a dopplervelocimetria é usada no acompanhamento de gestantes já sensibilizadas, não substituindo a profilaxia com imunoglobulina.' },
  { id: 'ufpr_gerado26_033', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Obstetrícia', text: 'Gestante, 25 anos, com rotura de membranas há 20 horas, apresenta febre materna, taquicardia fetal e líquido amniótico com odor fétido. O diagnóstico mais provável é:', options: ['corioamnionite.', 'placenta prévia.', 'pré-eclâmpsia.', 'descolamento prematuro de placenta.', 'rotura uterina.'], correctIndex: 0, explanation: 'Febre materna, taquicardia fetal e líquido fétido após rotura prolongada de membranas configuram corioamnionite, que exige antibioticoterapia e resolução da gestação. Placenta prévia cursa com sangramento indolor, sem febre; pré-eclâmpsia cursa com hipertensão e proteinúria, não com esse quadro infeccioso; descolamento prematuro cursa com dor súbita e hipertonia, sem esse padrão febril; rotura uterina cursa com dor abdominal aguda intensa, não com febre e líquido fétido como achados centrais.' },
  { id: 'ufpr_gerado26_034', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Obstetrícia', text: 'Em relação à indução do trabalho de parto, o Índice de Bishop avalia, entre outros parâmetros:', options: ['dilatação, esvaecimento, consistência e posição do colo uterino, além da altura da apresentação fetal.', 'exclusivamente a frequência cardíaca fetal basal.', 'apenas o peso estimado fetal por ultrassonografia.', 'exclusivamente o índice de líquido amniótico.', 'apenas a idade materna e o número de gestações prévias.'], correctIndex: 0, explanation: 'O Índice de Bishop avalia dilatação, esvaecimento, consistência e posição do colo, além da altura da apresentação fetal, para estimar a probabilidade de sucesso da indução. Frequência cardíaca fetal basal é avaliada pela cardiotocografia, não pelo Bishop; peso fetal estimado não compõe esse índice; índice de líquido amniótico é avaliado por ultrassonografia, não pelo Bishop; idade materna e paridade não são parâmetros do índice de Bishop.' },
  { id: 'ufpr_gerado26_035', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Obstetrícia', text: 'Gestante, 39 anos, com gestação gemelar dicoriônica de 12 semanas, tabagista, IMC 28. O principal fator de risco listado que justifica o uso de aspirina em baixa dose para prevenção de pré-eclâmpsia é:', options: ['a gestação gemelar.', 'o tabagismo.', 'o IMC de 28.', 'a idade materna isoladamente, sem qualquer outro fator associado.', 'a corionicidade dicoriônica isoladamente, independente de outros fatores.'], correctIndex: 0, explanation: 'A gestação múltipla é fator de risco de alto grau reconhecido para pré-eclâmpsia, justificando isoladamente a indicação de aspirina em baixa dose profilática. O tabagismo, isoladamente, não é classicamente listado como fator de risco de alto grau para pré-eclâmpsia nos principais protocolos; o IMC de 28 (sobrepeso) é fator de risco moderado, de menor peso isolado que a gestação múltipla; a idade materna isolada nessa faixa (39 anos) é fator de risco moderado, não o principal entre os listados; a corionicidade dicoriônica isoladamente não é o fator de risco central citado, sendo a gemelaridade em si o fator relevante.' },
  { id: 'ufpr_gerado26_036', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Obstetrícia', text: 'Puérpera, 15 dias após o parto, refere nódulo indolor na mama direita, sem febre. Ultrassom revela área cística de 2 cm no local. A conduta mais apropriada é:', options: ['controle clínico, considerando a hipótese de galactocele.', 'mastectomia imediata, sem qualquer investigação adicional.', 'quimioterapia empírica, sem biópsia ou confirmação diagnóstica.', 'antibioticoterapia isolada, independente de sinais infecciosos.', 'radioterapia isolada, sem qualquer avaliação complementar.'], correctIndex: 0, explanation: 'Nódulo cístico indolor no puerpério, sem sinais inflamatórios, é compatível com galactocele, geralmente conduzida com controle clínico. Mastectomia imediata é desproporcional para essa hipótese benigna mais provável; quimioterapia empírica sem diagnóstico é inadequada; antibioticoterapia isolada não é indicada na ausência de sinais infecciosos (febre, hiperemia); radioterapia não tem papel nessa condição benigna.' },
  { id: 'ufpr_gerado26_037', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Em relação aos princípios doutrinários do Sistema Único de Saúde, a equidade é definida como o princípio que busca:', options: ['reduzir desigualdades, ofertando mais recursos e atenção a quem mais necessita.', 'garantir tratamento estritamente igual a todos, independente das diferenças de necessidade.', 'restringir o acesso aos serviços de saúde a grupos populacionais específicos.', 'centralizar toda a decisão sanitária exclusivamente no nível federal.', 'limitar o acesso à atenção básica apenas a quem contribui financeiramente com o sistema.'], correctIndex: 0, explanation: 'A equidade busca reduzir desigualdades, ofertando mais atenção e recursos a quem mais necessita, reconhecendo que tratar desiguais de forma igual perpetua desigualdades. Garantir tratamento estritamente igual a todos, ignorando diferenças de necessidade, não corresponde ao conceito de equidade; a equidade não implica restrição de acesso a grupos específicos; a organização do SUS é descentralizada, não centralizada exclusivamente no nível federal; o SUS é de acesso universal e gratuito, não condicionado a contribuição financeira direta.' },
  { id: 'ufpr_gerado26_038', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Em relação à notificação compulsória de doenças, o sarampo deve ser notificado:', options: ['de forma compulsória e imediata, dado seu alto potencial de causar surtos.', 'apenas em caso de óbito associado ao caso.', 'mensalmente, de forma consolidada, sem urgência.', 'apenas quando há confirmação laboratorial, nunca diante de caso suspeito.', 'somente se o paciente for menor de 1 ano de idade.'], correctIndex: 0, explanation: 'O sarampo é doença de notificação compulsória imediata, dado seu alto potencial de gerar surtos epidêmicos. Notificar apenas em caso de óbito ignora a exigência diante de qualquer caso confirmado ou suspeito; notificação mensal consolidada é incompatível com a urgência exigida por essa doença; a notificação deve ocorrer diante de suspeita, não apenas após confirmação laboratorial; não há restrição de notificação por faixa etária específica.' },
  { id: 'ufpr_gerado26_039', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Em um estudo epidemiológico do tipo coorte, a medida de associação típica entre exposição e desfecho é:', options: ['o risco relativo.', 'a razão de chances (odds ratio).', 'a prevalência pontual.', 'a mortalidade proporcional.', 'o coeficiente de correlação de Pearson isolado.'], correctIndex: 0, explanation: 'O risco relativo é a medida de associação característica de estudos de coorte, comparando a incidência entre expostos e não expostos. A razão de chances é típica de estudos caso-controle, não de coorte; a prevalência pontual é medida de estudos transversais; a mortalidade proporcional descreve a distribuição de óbitos por causa, sem relação direta com esse desenho; o coeficiente de correlação de Pearson mede associação linear entre variáveis contínuas, não é a medida de associação padrão de coortes.' },
  { id: 'ufpr_gerado26_040', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Em relação à Estratégia Saúde da Família, o conceito de território adscrito se refere:', options: ['à área geográfica delimitada, com população definida, sob responsabilidade de uma equipe de saúde para planejamento e cuidado longitudinal.', 'exclusivamente aos limites administrativos municipais, sem relação com equipes de saúde.', 'à área de atuação restrita a hospitais terciários e quaternários.', 'a uma unidade de medida populacional sem qualquer relação com localização geográfica.', 'a áreas exclusivamente rurais, não sendo aplicável a contextos urbanos.'], correctIndex: 0, explanation: 'O território adscrito refere-se à área geográfica delimitada com população definida, sob responsabilidade de uma equipe de saúde da família, permitindo planejamento e cuidado longitudinal. Não se limita aos limites administrativos municipais, podendo ser subdivisão dentro do município; não se refere à atuação de hospitais terciários e quaternários, mas à atenção primária; é conceito geográfico e populacional combinado, não apenas uma unidade de medida populacional; é aplicável tanto a contextos urbanos quanto rurais, não exclusivo de áreas rurais.' },
  { id: 'ufpr_gerado26_041', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Em relação à vigilância de eventos adversos pós-vacinação (EAPV), é correto afirmar que:', options: ['a notificação de EAPV é essencial para a segurança do programa de imunização, sem implicar contraindicação automática a doses futuras.', 'todo EAPV contraindica automaticamente qualquer vacina futura, independente de investigação do nexo causal.', 'EAPV nunca deve ser notificado, para não gerar hesitação vacinal na população.', 'a notificação de EAPV é atribuição exclusiva do fabricante da vacina.', 'apenas EAPV graves com óbito devem ser notificados ao sistema de vigilância.'], correctIndex: 0, explanation: 'A notificação de EAPV é essencial para a vigilância e segurança do programa de imunização, sem implicar contraindicação automática a doses futuras, que depende da avaliação do nexo causal. Afirmar contraindicação automática ignora essa avaliação necessária; não notificar por medo de hesitação vacinal contraria o dever de vigilância; a notificação não é exclusiva do fabricante, sendo também responsabilidade dos profissionais de saúde; a notificação deve ocorrer para EAPV de diferentes gravidades, não apenas para óbitos.' },
  { id: 'ufpr_gerado26_042', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Em relação aos determinantes sociais da saúde, é correto afirmar que:', options: ['incluem condições de moradia, renda, escolaridade e acesso a saneamento básico, interagindo com determinantes biológicos.', 'atuam de forma completamente independente dos determinantes biológicos, sem qualquer interação.', 'não têm qualquer relação com políticas intersetoriais de enfrentamento.', 'se restringem exclusivamente a fatores genéticos individuais.', 'são irrelevantes para o planejamento em saúde pública.'], correctIndex: 0, explanation: 'Os determinantes sociais incluem moradia, renda, escolaridade e saneamento, entre outros, interagindo com determinantes biológicos no processo saúde-doença. Afirmar independência completa dos determinantes biológicos ignora essa interação constante; políticas intersetoriais são justamente uma resposta ao enfrentamento de determinantes sociais desfavoráveis; determinantes sociais não se restringem a fatores genéticos, sendo conceito distinto; são altamente relevantes para o planejamento em saúde pública, não irrelevantes.' },
  { id: 'ufpr_gerado26_043', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Em relação aos modelos de sistemas de saúde, o modelo de Bismarck é caracterizado por:', options: ['financiamento baseado em contribuições sociais (seguro social), vinculadas ao vínculo empregatício.', 'financiamento exclusivamente por impostos gerais, com acesso universal independente de contribuição.', 'ausência completa de qualquer papel do Estado na regulação da saúde.', 'financiamento exclusivamente por pagamento direto do paciente ao prestador de serviço (bem de consumo).', 'ser o modelo adotado integralmente pelo Brasil desde a criação do SUS.'], correctIndex: 0, explanation: 'O modelo de Bismarck se baseia em contribuições sociais (seguro social), vinculadas ao vínculo empregatício, para financiamento da saúde. O financiamento por impostos gerais com acesso universal caracteriza o modelo Beveridge, não o de Bismarck; o modelo de Bismarck envolve regulação estatal significativa sobre os fundos de seguro, não ausência de papel do Estado; o financiamento exclusivamente por pagamento direto caracteriza o modelo de mercado, não o de Bismarck; o Brasil adota o modelo de saúde como direito universal (mais próximo do Beveridge), não o de Bismarck.' },
  { id: 'ufpr_gerado26_044', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Em relação ao rastreamento populacional de doenças, o viés de tempo de antecipação (lead time bias) tem como principal consequência:', options: ['superestimar o benefício aparente do rastreamento sobre a sobrevida, sem necessariamente refletir aumento real da vida do paciente.', 'subestimar sistematicamente a sobrevida em todos os cenários de rastreamento.', 'eliminar completamente qualquer viés na avaliação de programas de rastreamento.', 'não ter qualquer relação com a interpretação de dados de sobrevida em rastreamento.', 'aumentar exclusivamente a especificidade do teste de rastreio, sem afetar a sobrevida aparente.'], correctIndex: 0, explanation: 'O viés de tempo de antecipação superestima o benefício aparente do rastreamento sobre a sobrevida, pois antecipa o diagnóstico sem necessariamente prolongar a vida real do paciente. Não subestima a sobrevida, ao contrário, tende a superestimá-la; não elimina vieses, sendo justamente um viés relevante a ser considerado na avaliação de rastreamentos; tem relação direta e importante na interpretação de dados de sobrevida em programas de rastreio; não se relaciona com a especificidade do teste, mas com a interpretação do tempo de diagnóstico em relação à história natural da doença.' },
  { id: 'ufpr_gerado26_045', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Em relação à Rede de Atenção Psicossocial e ao papel do CAPS, é correto afirmar que:', options: ['atua na articulação do cuidado em saúde mental de base territorial e comunitária, com construção de projeto terapêutico singular.', 'tem como estratégia central a internação psiquiátrica prolongada em hospital especializado.', 'restringe-se ao atendimento de urgências psiquiátricas agudas, sem acompanhamento longitudinal.', 'não estabelece qualquer articulação com a atenção primária à saúde.', 'é destinado exclusivamente a pacientes com dependência química, sem outras condições de saúde mental.'], correctIndex: 0, explanation: 'O CAPS atua na articulação do cuidado em saúde mental de base territorial e comunitária, construindo projeto terapêutico singular para cada usuário. A Reforma Psiquiátrica brasileira preconiza justamente a substituição do modelo hospitalocêntrico pela atenção territorial, não a internação prolongada como estratégia central; o CAPS realiza acompanhamento longitudinal, não se restringindo a urgências agudas; articula-se com a atenção primária, não atuando de forma isolada; atende diversas condições de saúde mental, não exclusivamente dependência química (havendo, inclusive, modalidades específicas como CAPS AD para esse perfil).' },
  { id: 'ufpr_gerado26_046', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Homem, 62 anos, tabagista, com dispneia progressiva e baqueteamento digital, tomografia de tórax mostrando padrão reticular subpleural com faveolamento em bases. O diagnóstico mais provável é:', options: ['fibrose pulmonar idiopática.', 'sarcoidose pulmonar.', 'pneumonia em organização criptogênica.', 'histiocitose pulmonar de células de Langerhans.', 'asma brônquica de início tardio.'], correctIndex: 0, explanation: 'Faveolamento subpleural em bases com baqueteamento digital é o padrão radiológico clássico da fibrose pulmonar idiopática. A sarcoidose cursa com adenopatia hilar/mediastinal, não faveolamento basal; a POC apresenta consolidações migratórias, não faveolamento; a histiocitose de Langerhans acomete campos superiores com cistos, não faveolamento basal; asma cursaria com obstrução reversível, não com esse padrão de fibrose.' },
  { id: 'ufpr_gerado26_047', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Mulher, 40 anos, com fraqueza progressiva, hiperpigmentação cutânea difusa (incluindo pregas palmares e mucosa oral), hipotensão postural, hiponatremia e hipercalemia. O diagnóstico mais provável é:', options: ['insuficiência adrenal primária (doença de Addison).', 'síndrome de Cushing.', 'hipotireoidismo primário grave.', 'feocromocitoma.', 'diabetes insípido central.'], correctIndex: 0, explanation: 'Hiperpigmentação cutaneomucosa (por aumento de ACTH e do peptídeo relacionado à melanocortina), hipotensão, hiponatremia e hipercalemia formam o quadro clássico da insuficiência adrenal primária. A síndrome de Cushing cursa com excesso de cortisol, causando hipertensão e hipocalemia, não hipercalemia; o hipotireoidismo não causa hiperpigmentação nem esse distúrbio eletrolítico típico; o feocromocitoma cursa com hipertensão paroxística, não hipotensão; o diabetes insípido cursa com poliúria e hipernatremia, não hiponatremia com hipercalemia.' },
  { id: 'ufpr_gerado26_048', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Homem, 58 anos, com neoplasia pulmonar de células escamosas recém-diagnosticada, apresenta confusão mental, poliúria, constipação e cálcio sérico total de 13,2 mg/dL, com PTH sérico suprimido. O mecanismo mais provável da hipercalcemia é:', options: ['secreção tumoral de peptídeo relacionado ao PTH (PTHrP).', 'hiperparatireoidismo primário concomitante.', 'intoxicação por vitamina D exógena.', 'sarcoidose com granulomas produtores de calcitriol.', 'uso crônico de diuréticos tiazídicos como causa isolada.'], correctIndex: 0, explanation: 'Hipercalcemia com PTH suprimido em paciente com carcinoma escamoso é tipicamente mediada pela secreção tumoral de PTHrP (hipercalcemia humoral da malignidade). Hiperparatireoidismo primário cursaria com PTH elevado, não suprimido; intoxicação por vitamina D e sarcoidose cursam com PTH suprimido mas não há relação com a neoplasia relatada nem esse seria o mecanismo mais provável no contexto oncológico apresentado; diuréticos tiazídicos podem contribuir para hipercalcemia leve, mas não explicam isoladamente hipercalcemia grave associada a tumor sólido recém-diagnosticado.' },
  { id: 'ufpr_gerado26_049', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Homem, 55 anos, com hipertensão resistente e hipocalemia espontânea, atividade de renina plasmática suprimida e relação aldosterona/renina elevada. O diagnóstico mais provável é:', options: ['hiperaldosteronismo primário.', 'feocromocitoma.', 'síndrome de Cushing.', 'estenose de artéria renal bilateral.', 'hipotireoidismo grave.'], correctIndex: 0, explanation: 'Hipocalemia espontânea com renina suprimida e relação aldosterona/renina elevada é o padrão bioquímico clássico do hiperaldosteronismo primário. Feocromocitoma não apresenta esse padrão renina-aldosterona; síndrome de Cushing tem outro perfil hormonal; estenose de artéria renal bilateral cursaria com renina alta, não suprimida; hipotireoidismo não explica esse padrão bioquímico específico.' },
  { id: 'ufpr_gerado26_050', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Mulher, 32 anos, com dois abortamentos espontâneos no segundo trimestre e um episódio prévio de trombose venosa profunda não provocada, anticorpo anticardiolipina e anticoagulante lúpico positivos em duas ocasiões com 12 semanas de intervalo. O diagnóstico mais provável é:', options: ['síndrome do anticorpo antifosfolípide.', 'púrpura trombocitopênica trombótica.', 'deficiência isolada de proteína C.', 'síndrome hemolítico-urêmica.', 'trombocitopenia induzida por heparina.'], correctIndex: 0, explanation: 'Trombose venosa e perdas gestacionais recorrentes associadas à positividade persistente de anticorpos antifosfolípides (anticardiolipina e anticoagulante lúpico) confirmam a síndrome do anticorpo antifosfolípide. A púrpura trombocitopênica trombótica cursa com anemia hemolítica microangiopática e plaquetopenia, sem relação com esses autoanticorpos; a deficiência isolada de proteína C não explica a positividade desses anticorpos nem o padrão obstétrico completo; a síndrome hemolítico-urêmica cursa com insuficiência renal aguda e não com esse perfil sorológico; a trombocitopenia induzida por heparina depende de exposição prévia à heparina, não mencionada no caso.' },
  { id: 'ufpr_gerado26_051', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Homem, 68 anos, com cefaleia temporal, claudicação mandibular e VHS muito elevado. A principal complicação a ser prevenida com tratamento imediato é:', options: ['cegueira por neuropatia óptica isquêmica.', 'insuficiência renal aguda.', 'meningite bacteriana.', 'osteoporose grave.', 'trombose venosa profunda.'], correctIndex: 0, explanation: 'Cefaleia temporal e claudicação mandibular sugerem arterite de células gigantes; o corticoide deve ser iniciado prontamente para prevenir cegueira irreversível. Insuficiência renal aguda não é complicação típica dessa vasculite; meningite bacteriana não tem relação fisiopatológica com o quadro; osteoporose é efeito adverso tardio do próprio tratamento, não complicação da doença a prevenir com urgência; trombose venosa profunda não é a complicação central a ser evitada nessa condição.' },
  { id: 'ufpr_gerado26_052', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Mulher, 50 anos, com poliartrite simétrica de pequenas articulações das mãos, rigidez matinal prolongada, fator reumatoide e anti-CCP positivos, erosões periarticulares. A classe medicamentosa a ser iniciada precocemente é:', options: ['droga modificadora do curso da doença (como o metotrexato).', 'apenas anti-inflamatório em longo prazo.', 'opioide de forma contínua.', 'corticoide isolado como única terapia permanente.', 'apenas fisioterapia, sem qualquer medicação.'], correctIndex: 0, explanation: 'O metotrexato, droga modificadora do curso da artrite reumatoide, deve ser iniciado precocemente para evitar dano articular progressivo. Anti-inflamatório isolado controla sintomas mas não impede a progressão erosiva; opioide contínuo não trata a doença de base; corticoide isolado como terapia permanente expõe a efeitos adversos cumulativos sem modificar o curso da doença; fisioterapia isolada, sem medicação modificadora, não impede a progressão do dano articular.' },
  { id: 'ufpr_gerado26_053', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Homem, 60 anos, com dispneia paroxística noturna, ortopneia e BNP muito elevado, fração de ejeção de 30%, já em uso otimizado de IECA, betabloqueador e antagonista mineralocorticoide. A próxima classe terapêutica a ser considerada é:', options: ['inibidor do cotransportador sódio-glicose tipo 2.', 'bloqueador de canal de cálcio di-hidropiridínico.', 'anti-inflamatório não esteroidal.', 'antiarrítmico classe IC.', 'apenas aumento da dose de diurético de alça, sem outra classe terapêutica.'], correctIndex: 0, explanation: 'Os inibidores de SGLT2 fazem parte da terapia quádrupla atual da insuficiência cardíaca com fração de ejeção reduzida, sendo o próximo passo após otimização das demais classes. Bloqueador de canal de cálcio di-hidropiridínico não tem benefício de mortalidade comprovado; anti-inflamatório é contraindicado por piorar retenção hidrossalina; antiarrítmico classe IC é contraindicado em cardiopatia estrutural; aumentar apenas o diurético trata sintomas congestivos, sem o benefício prognóstico da terapia quádrupla completa.' },
  { id: 'ufpr_gerado26_054', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Homem, 48 anos, com diarreia crônica, dor abdominal, artralgia migratória, perda ponderal importante e linfadenopatia, biópsia de intestino delgado com macrófagos PAS-positivos na lâmina própria. O diagnóstico e o tratamento são, respectivamente:', options: ['doença de Whipple; antibioticoterapia prolongada.', 'doença celíaca; dieta isenta de glúten.', 'linfoma intestinal; quimioterapia isolada.', 'doença de Crohn; imunobiológico anti-TNF isolado.', 'giardíase crônica; apenas hidratação, sem antiparasitário.'], correctIndex: 0, explanation: 'Macrófagos PAS-positivos na lâmina própria associados a diarreia crônica, artralgia migratória e linfadenopatia são achado patognomônico da doença de Whipple, tratada com antibioticoterapia prolongada. Doença celíaca não apresenta esse achado histológico nem cursa tipicamente com artralgia migratória e linfadenopatia proeminentes; linfoma intestinal teria achado histológico de infiltrado neoplásico, não macrófagos PAS-positivos; doença de Crohn cursaria com granulomas não caseosos, não macrófagos PAS-positivos; giardíase crônica não explica esse achado histológico específico nem seria tratada apenas com hidratação.' },
  { id: 'ufpr_gerado26_055', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Homem, 45 anos, com dor abdominal em faixa irradiada para o dorso após ingestão alcoólica importante, lipase 6 vezes o valor de referência. A conduta inicial mais apropriada é:', options: ['hidratação venosa vigorosa, analgesia e dieta conforme tolerância.', 'antibioticoterapia profilática de rotina.', 'cirurgia pancreática imediata.', 'CPRE de urgência independente de obstrução biliar.', 'jejum absoluto prolongado por 2 semanas, independente da evolução clínica.'], correctIndex: 0, explanation: 'O tratamento inicial da pancreatite aguda é hidratação venosa vigorosa, analgesia adequada e dieta conforme tolerância, sem antibiótico profilático de rotina. Antibioticoterapia profilática não é recomendada na ausência de infecção confirmada; cirurgia imediata não é indicada na fase inicial não complicada; CPRE de urgência é reservada a obstrução biliar concomitante; jejum absoluto prolongado sem necessidade prejudica a recuperação nutricional, sendo a dieta precoce conforme tolerância a conduta atual preferida.' },
  { id: 'ufpr_gerado26_056', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Infectologia', text: 'Homem, 35 anos, retorna de área endêmica com febre alta, mialgia intensa, exantema no 4.º dia, dor abdominal intensa persistente e sangramento de mucosa. A classificação de gravidade e a conduta são:', options: ['dengue com sinais de alarme; internação para hidratação venosa e monitorização.', 'dengue sem sinais de alarme; alta com hidratação oral apenas.', 'febre amarela; vacinação imediata como tratamento.', 'zika vírus; apenas sintomáticos e alta.', 'chikungunya; apenas analgesia, sem necessidade de internação.'], correctIndex: 0, explanation: 'Dor abdominal intensa e sangramento de mucosa são sinais de alarme na dengue, exigindo internação para hidratação venosa e monitorização. Classificar como dengue sem sinais de alarme ignora os sinais presentes; vacinação não trata febre amarela já instalada; zika e chikungunya não costumam cursar com esses sinais de alarme hemorrágicos e abdominais tão específicos da dengue.' },
  { id: 'ufpr_gerado26_057', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Infectologia', text: 'Homem, 35 anos, com lesões cutâneas hipocrômicas com alteração de sensibilidade térmica e dolorosa, espessamento de nervo ulnar palpável, baciloscopia de esfregaço intradérmico positiva, múltiplas lesões acima de 5. A classificação operacional e o esquema terapêutico padrão são, respectivamente:', options: ['hanseníase multibacilar; poliquimioterapia com rifampicina, dapsona e clofazimina por 12 meses.', 'hanseníase paucibacilar; poliquimioterapia com rifampicina e dapsona por 6 meses.', 'hanseníase indeterminada; apenas corticoide tópico, sem antibioticoterapia.', 'tuberculose cutânea; esquema RIPE por 6 meses.', 'leishmaniose cutânea; antimonial pentavalente por 20 dias.'], correctIndex: 0, explanation: 'Baciloscopia positiva e mais de 5 lesões classificam o caso como hanseníase multibacilar, tratada com poliquimioterapia de rifampicina, dapsona e clofazimina por 12 meses. A forma paucibacilar tem baciloscopia negativa e até 5 lesões, com esquema de 6 meses sem clofazimina; a forma indeterminada não cursa com baciloscopia positiva nem exigiria apenas corticoide tópico; tuberculose cutânea não explica o espessamento de nervo periférico nem a baciloscopia de esfregaço intradérmico positiva; leishmaniose cutânea cursa com úlceras de bordas elevadas, não com esse padrão de alteração de sensibilidade e espessamento neural.' },
  { id: 'ufpr_gerado26_058', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Infectologia', text: 'Homem, 30 anos, HIV positivo, CD4 de 90 células/mm³, com cefaleia progressiva e lesão com realce em anel em núcleos da base. O tratamento empírico inicial mais apropriado é:', options: ['sulfadiazina associada a pirimetamina e ácido folínico.', 'ceftriaxona isolada.', 'anfotericina B isolada, sem investigação de imagem.', 'quimioterapia isolada, sem tratamento empírico prévio.', 'apenas corticoide isolado, sem cobertura antiparasitária.'], correctIndex: 0, explanation: 'Lesão com realce em anel em núcleos da base em paciente com CD4 baixo é altamente sugestiva de neurotoxoplasmose, tratada empiricamente com sulfadiazina, pirimetamina e ácido folínico. Ceftriaxona cobre bactérias, não o protozoário Toxoplasma; anfotericina B é direcionada a fungos; quimioterapia isolada seria voltada a linfoma primário do SNC, considerado apenas após falha do tratamento empírico; corticoide isolado sem cobertura antiparasitária não trata a causa infecciosa provável.' },
  { id: 'ufpr_gerado26_059', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Medicina Legal', text: 'Em relação ao Código de Ética Médica, o sigilo profissional pode ser quebrado, entre outras situações, diante de:', options: ['justa causa, como risco iminente à vida de terceiros, respeitados os limites legais.', 'qualquer solicitação de autoridade, sem necessidade de base legal específica.', 'pedido informal de familiares, sem qualquer outro critério.', 'curiosidade de outros profissionais de saúde não envolvidos no caso.', 'interesse comercial de terceiros na informação do paciente.'], correctIndex: 0, explanation: 'O sigilo médico pode ser quebrado por justa causa, como risco iminente à vida de terceiros, respeitados os limites legais estabelecidos. Quebrar o sigilo diante de qualquer solicitação de autoridade, sem base legal específica, não é eticamente correto; pedido informal de familiares não configura justa causa para quebra de sigilo; curiosidade de profissionais não envolvidos no caso não justifica a quebra; interesse comercial de terceiros nunca justifica a quebra do sigilo médico.' },
  { id: 'ufpr_gerado26_060', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Medicina Legal', text: 'Em relação às diretivas antecipadas de vontade (testamento vital), é correto afirmar que:', options: ['permitem que o paciente registre suas preferências para tratamentos futuros, a serem respeitadas caso perca a capacidade de decisão.', 'têm validade apenas para o procedimento específico realizado no momento de sua assinatura.', 'substituem completamente a necessidade de qualquer consentimento informado futuro em qualquer contexto.', 'só podem ser elaboradas por pacientes já em estado terminal confirmado.', 'não têm qualquer respaldo ético reconhecido na prática médica brasileira.'], correctIndex: 0, explanation: 'As diretivas antecipadas de vontade permitem que o paciente registre suas preferências para tratamentos futuros, a serem respeitadas caso perca a capacidade de decisão. Diferem do consentimento informado padrão, que vale para um procedimento específico no momento presente, não tendo essa validade prospectiva limitada; não substituem toda necessidade de consentimento futuro em qualquer contexto, mas orientam decisões quando o paciente não pode mais se manifestar; podem ser elaboradas por qualquer pessoa capaz, não apenas por pacientes já terminais; têm respaldo ético reconhecido na prática médica brasileira.' },
  { id: 'ufpr_gerado26_061', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Medicina Legal', text: 'Em relação à responsabilidade civil médica por erro de prescrição que causa dano ao paciente, por desatenção a alergia registrada em prontuário, é correto afirmar que:', options: ['trata-se de responsabilidade subjetiva, exigindo comprovação de culpa (negligência, imprudência ou imperícia).', 'trata-se de responsabilidade objetiva, independente de qualquer culpa.', 'não há qualquer responsabilidade, pois erros de prescrição são sempre escusáveis.', 'a responsabilidade é exclusivamente institucional, sem qualquer responsabilidade pessoal do médico.', 'a responsabilidade só existiria se o dano fosse permanente e irreversível.'], correctIndex: 0, explanation: 'A responsabilidade civil médica é, em regra, subjetiva, exigindo comprovação de culpa para configurar erro médico indenizável. Responsabilidade objetiva independeria de culpa, o que não é a regra geral aplicada à conduta médica pessoal; afirmar ausência de responsabilidade ignora que a desatenção a um dado registrado configura negligência; atribuir a responsabilidade exclusivamente à instituição ignora a responsabilidade pessoal do profissional; a responsabilidade pode existir mesmo em danos temporários, não sendo restrita a danos permanentes e irreversíveis.' },
  { id: 'ufpr_gerado26_062', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Neurologia', text: 'Mulher, 27 anos, com episódios recorrentes de perda visual unilateral, parestesias e fraqueza em membros, ressonância magnética evidenciando lesões desmielinizantes disseminadas no espaço e no tempo. O diagnóstico mais provável é:', options: ['esclerose múltipla.', 'acidente vascular cerebral de repetição.', 'miastenia gravis.', 'síndrome de Guillain-Barré.', 'enxaqueca com aura, sem lesões estruturais.'], correctIndex: 0, explanation: 'Lesões desmielinizantes disseminadas no espaço e no tempo são o critério diagnóstico central da esclerose múltipla. AVC de repetição teria lesões vasculares, não desmielinizantes; miastenia gravis não apresenta lesões de substância branca; Guillain-Barré cursa com fraqueza ascendente aguda e arreflexia, não com esse padrão de lesões na ressonância; enxaqueca com aura não deixa lesões estruturais persistentes características.' },
  { id: 'ufpr_gerado26_063', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Neurologia', text: 'Homem, 58 anos, com fraqueza muscular com fadiga que piora ao longo do dia, ptose e diplopia flutuantes, melhora da ptose ao teste do gelo. O diagnóstico mais provável é:', options: ['miastenia gravis.', 'esclerose lateral amiotrófica.', 'síndrome de Guillain-Barré.', 'distrofia muscular de Duchenne.', 'polimiosite isolada.'], correctIndex: 0, explanation: 'Fraqueza flutuante que piora ao longo do dia, com melhora da ptose ao teste do gelo, é característica da miastenia gravis. Esclerose lateral amiotrófica cursa com fraqueza progressiva não flutuante e sinais de neurônio motor superior e inferior; Guillain-Barré cursa com fraqueza ascendente aguda e arreflexia; distrofia de Duchenne acomete meninos na infância; polimiosite não cursa com ptose e diplopia flutuantes como achados centrais.' },
  { id: 'ufpr_gerado26_064', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Medicina de Família', text: 'Em relação ao método clínico centrado na pessoa, é correto afirmar que:', options: ['busca compreender a doença e também a experiência de adoecimento vivida pelo paciente, considerando contexto familiar e social.', 'prioriza exclusivamente o diagnóstico biomédico, sem espaço para expectativas do paciente.', 'restringe a decisão terapêutica exclusivamente ao médico, sem participação do paciente.', 'é aplicável apenas em consultas de longa duração, nunca em atendimentos breves.', 'exclui qualquer consideração sobre o contexto de vida do paciente.'], correctIndex: 0, explanation: 'O método clínico centrado na pessoa busca compreender a doença e a experiência de adoecimento, considerando contexto familiar e social do paciente. Priorizar exclusivamente o diagnóstico biomédico contraria a essência do método; restringir a decisão exclusivamente ao médico contraria o princípio de decisão compartilhada; o método pode ser aplicado mesmo em consultas breves, adaptando sua profundidade; o contexto de vida do paciente é justamente elemento central desse método, não excluído dele.' },
  { id: 'ufpr_gerado26_065', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Medicina de Família', text: 'Em relação à prevenção quaternária na atenção primária, é correto afirmar que:', options: ['busca evitar intervenções médicas desnecessárias ou potencialmente prejudiciais.', 'tem como objetivo aumentar sistematicamente o número de exames solicitados por consulta.', 'aplica-se exclusivamente a pacientes oncológicos em cuidados paliativos.', 'é sinônimo de prevenção terciária, sem qualquer distinção conceitual.', 'não tem qualquer relação com a solicitação racional de exames complementares.'], correctIndex: 0, explanation: 'A prevenção quaternária busca proteger o paciente de intervenções desnecessárias ou potencialmente prejudiciais, incluindo exames sem indicação clara. Aumentar sistematicamente o número de exames contraria diretamente esse objetivo; não se restringe a pacientes oncológicos paliativos, aplicando-se a qualquer contexto de sobremedicalização; não é sinônimo de prevenção terciária (reabilitação de doença já instalada), sendo conceito distinto; tem relação direta com a solicitação racional e criteriosa de exames complementares.' },
  { id: 'ufpr_gerado26_066', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Mastologia', text: 'Mulher, 52 anos, sem histórico familiar de câncer de mama, com massa palpável na mama esquerda, mamografia com lesão espiculada BI-RADS 5, biópsia confirmando carcinoma invasivo com receptores hormonais positivos e HER2 negativo. A avaliação axilar em axila clinicamente negativa deve priorizar:', options: ['pesquisa do linfonodo sentinela, com menor morbidade que o esvaziamento axilar completo.', 'esvaziamento axilar completo obrigatório em toda paciente, independente do exame clínico.', 'nenhuma avaliação axilar, dado que a axila está clinicamente negativa.', 'radioterapia axilar isolada, sem qualquer avaliação cirúrgica.', 'quimioterapia isolada, sem qualquer avaliação do status axilar.'], correctIndex: 0, explanation: 'Em axila clinicamente negativa, a pesquisa do linfonodo sentinela é a estratégia recomendada para avaliar o status axilar com menor morbidade que o esvaziamento completo. Esvaziamento axilar completo obrigatório em toda paciente é conduta ultrapassada e desproporcional; a ausência de linfonodos palpáveis não exclui micrometástases, exigindo avaliação; radioterapia axilar isolada não substitui a avaliação cirúrgica do status linfonodal; quimioterapia isolada sem avaliação axilar ignora informação estadiadora relevante para o planejamento terapêutico.' },
  { id: 'ufpr_gerado26_067', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Mastologia', text: 'Puérpera, 15 dias após o parto, refere nódulo indolor na mama direita, sem febre, ultrassom evidenciando área cística de 2 cm no local. Assinale a alternativa correta sobre a conduta.', options: ['controle clínico, considerando a hipótese de galactocele, achado benigno comum no puerpério.', 'mastectomia imediata, sem qualquer investigação adicional.', 'quimioterapia empírica, sem biópsia ou confirmação diagnóstica.', 'antibioticoterapia isolada, independente de sinais infecciosos presentes.', 'radioterapia isolada, sem qualquer avaliação complementar prévia.'], correctIndex: 0, explanation: 'Nódulo cístico indolor no puerpério, sem sinais inflamatórios, é compatível com galactocele, achado benigno comum nessa fase, geralmente conduzido com controle clínico. Mastectomia imediata é desproporcional para essa hipótese benigna mais provável; quimioterapia empírica sem diagnóstico é inadequada; antibioticoterapia isolada não é indicada na ausência de sinais infecciosos; radioterapia não tem papel nessa condição benigna.' },
  { id: 'ufpr_gerado26_068', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cardiologia', text: 'Mulher, 68 anos, com síncope aos esforços, sopro sistólico rude em foco aórtico irradiado para carótidas, ecocardiograma evidenciando área valvar aórtica de 0,7 cm². A conduta definitiva é:', options: ['troca valvar aórtica, cirúrgica ou por via transcateter conforme risco.', 'tratamento clínico exclusivo, sem qualquer intervenção sobre a válvula.', 'apenas seguimento ecocardiográfico anual, sem qualquer intervenção.', 'betabloqueador em altas doses como única conduta.', 'diurético isolado, sem qualquer intervenção sobre a válvula estenosada.'], correctIndex: 0, explanation: 'Estenose aórtica grave sintomática (síncope) tem indicação de troca valvar, cirúrgica ou transcateter conforme o risco do paciente. Tratamento clínico exclusivo não modifica a obstrução mecânica nem reduz o risco de morte súbita; seguimento isolado é apropriado apenas para estenose assintomática; betabloqueador em altas doses pode ser deletério nessa condição; diurético isolado não trata a causa obstrutiva estrutural da valva.' },
  { id: 'ufpr_gerado26_069', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Recém-nascido a termo, nas primeiras horas de vida, apresenta vômitos biliosos, distensão abdominal leve e radiografia simples de abdome com dupla bolha gástrica sem gás distal. A hipótese diagnóstica mais provável e a urgência da conduta são:', options: ['má rotação intestinal com volvo de intestino médio; cirurgia de urgência pelo risco de necrose intestinal extensa.', 'estenose hipertrófica do piloro; correção hidroeletrolítica e cirurgia eletiva após estabilização.', 'atresia de esôfago isolada; gastrostomia eletiva.', 'doença de Hirschsprung; biópsia retal ambulatorial, sem urgência cirúrgica.', 'refluxo gastroesofágico fisiológico; apenas espessamento da fórmula láctea.'], correctIndex: 0, explanation: 'Vômitos biliosos no recém-nascido com o padrão radiológico de dupla bolha sem gás distal sugerem má rotação intestinal com volvo de intestino médio, emergência cirúrgica pelo risco de necrose extensa do intestino. A estenose hipertrófica do piloro cursa com vômitos não biliosos e surge tipicamente após a segunda semana de vida, não nas primeiras horas; a atresia de esôfago isolada cursaria com sialorreia e impossibilidade de progressão de sonda orogástrica, não vômitos biliosos; a doença de Hirschsprung cursa com atraso de eliminação de mecônio e distensão progressiva, não é emergência cirúrgica imediata da mesma forma; refluxo fisiológico não cursa com vômitos biliosos nem esse achado radiológico.' },
  { id: 'ufpr_gerado26_070', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Criança, 5 anos, não vacinada, com febre alta, tosse, coriza e conjuntivite há 3 dias, seguidos do surgimento de exantema maculopapular que se inicia na face e progride em sentido cefalocaudal, com manchas esbranquiçadas em mucosa jugal. A principal complicação tardia a ser considerada nesse quadro é:', options: ['panencefalite esclerosante subaguda.', 'aneurisma de artérias coronárias.', 'glomerulonefrite pós-infecciosa.', 'febre reumática.', 'síndrome hemolítico-urêmica.'], correctIndex: 0, explanation: 'O quadro descrito (pródromo catarral, manchas de Koplik e exantema cefalocaudal) é típico do sarampo, cuja complicação tardia rara mas grave é a panencefalite esclerosante subaguda, anos após a infecção. Aneurisma coronariano é complicação da doença de Kawasaki, não do sarampo; glomerulonefrite pós-infecciosa relaciona-se a infecção estreptocócica, não ao sarampo; febre reumática também decorre de infecção estreptocócica; síndrome hemolítico-urêmica relaciona-se predominantemente a infecção por E. coli êntero-hemorrágica, sem relação com o sarampo.' },
  { id: 'ufpr_gerado26_071', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Lactente, 14 meses, previamente hígido, apresenta episódio único de sangramento retal indolor, volumoso, de coloração vermelho-vivo, sem dor abdominal, distensão ou vômitos associados. A hipótese diagnóstica mais provável e o exame confirmatório de escolha são, respectivamente:', options: ['divertículo de Meckel; cintilografia com pertecnetato de tecnécio-99m.', 'invaginação intestinal; enema hidrostático guiado por imagem.', 'fissura anal; inspeção perianal isolada.', 'pólipo juvenil retal; apenas toque retal, sem outro exame.', 'doença hemorrágica do recém-nascido; dosagem de vitamina K.'], correctIndex: 0, explanation: 'Sangramento retal indolor e volumoso, sem dor abdominal ou massa palpável, é o quadro clássico do divertículo de Meckel sangrante por mucosa gástrica ectópica, confirmado pela cintilografia com pertecnetato. A invaginação intestinal cursaria com dor em cólica, choro intermitente e frequentemente massa palpável, ausentes no caso; a fissura anal causa sangramento em pequena quantidade associado à evacuação, não sangramento volumoso indolor; o pólipo juvenil costuma causar sangramento de menor volume e é diagnosticado por colonoscopia, não apenas toque retal; a doença hemorrágica do recém-nascido ocorre nos primeiros dias de vida, não aos 14 meses.' },
  { id: 'ufpr_gerado26_072', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Criança, 6 anos, com enurese noturna isolada e exame físico normal. A conduta inicial é:', options: ['orientação comportamental e reasseguramento.', 'desmopressina imediata sem orientação comportamental prévia.', 'investigação urológica invasiva imediata.', 'restrição hídrica extrema durante todo o dia.', 'encaminhamento imediato para cirurgia urológica, sem qualquer abordagem clínica prévia.'], correctIndex: 0, explanation: 'Enurese isolada sem sinais de alarme é tratada inicialmente com orientação comportamental, reservando medicação para casos persistentes. Desmopressina imediata sem tentativa comportamental prévia pula uma etapa terapêutica de primeira linha; investigação urológica invasiva não é indicada na ausência de sinais de alarme; restrição hídrica extrema é inadequada e pode causar desidratação; cirurgia não é indicada para esse quadro funcional isolado.' },
  { id: 'ufpr_gerado26_073', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Lactente, 6 semanas de vida, com icterícia progressiva iniciada na terceira semana, colúria, fezes acólicas persistentes e hepatomegalia, bilirrubina direta elevada. A conduta mais apropriada é:', options: ['investigação urgente para atresia de vias biliares, incluindo ultrassonografia e biópsia hepática, visando cirurgia (portoenterostomia de Kasai) antes dos 60 dias de vida.', 'observação clínica ambulatorial até os 6 meses de vida, sem investigação adicional.', 'fototerapia isolada, sem investigação da causa da colestase.', 'suspensão do aleitamento materno como única conduta diagnóstica e terapêutica.', 'antibioticoterapia empírica isolada, sem investigação de causa colestática.'], correctIndex: 0, explanation: 'Icterícia colestática com acolia fecal persistente após a segunda semana de vida exige investigação urgente para atresia de vias biliares, pois o sucesso da portoenterostomia de Kasai depende de intervenção precoce, idealmente antes dos 60 dias de vida. Observar até os 6 meses atrasaria perigosamente uma cirurgia tempo-dependente; fototerapia trata hiperbilirrubinemia indireta, não a colestase por obstrução biliar; suspender o aleitamento materno não elucida nem trata uma causa obstrutiva biliar; antibioticoterapia empírica não trata a causa estrutural da colestase.' },
  { id: 'ufpr_gerado26_074', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Lactente de 8 meses, previamente hígido, com tosse, coriza e sibilância há 2 dias, desconforto respiratório leve, primeiro episódio de sibilância, teste rápido positivo para vírus sincicial respiratório. A conduta é:', options: ['suporte com lavagem nasal, oxigenoterapia se necessário e hidratação, sem broncodilatador, corticoide ou antibiótico de rotina.', 'corticoide sistêmico em dose única, indicado rotineiramente para reduzir o tempo de internação.', 'antibioticoterapia empírica de rotina, dada a alta taxa de coinfecção bacteriana.', 'broncodilatador inalatório de rotina e continuado em todos os casos.', 'internação obrigatória em UTI, independente da gravidade do desconforto respiratório.'], correctIndex: 0, explanation: 'O tratamento da bronquiolite viral aguda é essencialmente de suporte, sem benefício comprovado de broncodilatador, corticoide ou antibiótico de rotina. Corticoide sistêmico não reduz tempo de internação nessa condição; antibioticoterapia empírica não é indicada sem sinais de infecção bacteriana concomitante; broncodilatador de rotina não tem eficácia comprovada na bronquiolite; internação em UTI não é obrigatória para todo caso, dependendo da gravidade do desconforto respiratório.' },
  { id: 'ufpr_gerado26_075', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Menino de 9 anos apresentou há 1 ano febre, poliartrite migratória e cardite, com VHS elevado e ASLO elevado. A duração da profilaxia secundária com penicilina benzatina é definida principalmente por:', options: ['o comprometimento cardíaco (presença e gravidade da cardite).', 'o comprometimento articular isolado, sem relação com a cardite.', 'o nível sérico de ASLO isoladamente, sem relação com a gravidade clínica.', 'o valor do VHS na fase aguda, sem relação com o comprometimento cardíaco.', 'a idade da criança no momento do primeiro surto, sem qualquer outro critério.'], correctIndex: 0, explanation: 'A duração da profilaxia secundária da febre reumática é definida principalmente pelo comprometimento cardíaco (presença e gravidade da cardite), sendo mais prolongada em casos com lesão valvar residual. O comprometimento articular isolado, sem cardite, não determina a duração da profilaxia da mesma forma; o nível de ASLO não é o critério que define a duração da profilaxia; o valor do VHS na fase aguda reflete atividade inflamatória, não sendo o critério central da duração profilática; a idade isolada não é o principal critério, embora seja considerada em conjunto com o comprometimento cardíaco.' },
  { id: 'ufpr_gerado26_076', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Lactente de 2 meses, assintomático, nascido pequeno para a idade gestacional, em aleitamento artificial, com resultado positivo para fenilcetonúria na triagem neonatal coletada com 24 horas de vida, não confirmado em amostras posteriores. O fator que justifica a discordância entre os resultados é:', options: ['a idade da coleta da primeira amostra, muito precoce, associada a possíveis interferentes.', 'a suspensão completa do aleitamento artificial entre as coletas.', 'a hiperfenilalaninemia materna isolada, sem qualquer relação com a idade de coleta.', 'a restrição de crescimento intrauterino isoladamente, sem relação com o momento da coleta.', 'erro laboratorial sistemático que sempre ocorre nas amostras coletadas após 48 horas de vida.'], correctIndex: 0, explanation: 'A coleta muito precoce (24 horas) da triagem neonatal está associada a maior taxa de resultados falso-positivos, incluindo para fenilcetonúria, justificando a discordância com amostras posteriores. Não há suspensão do aleitamento artificial mencionada como causa da discordância; hiperfenilalaninemia materna é causa possível de alteração transitória, mas o fator mais diretamente relacionado no caso é a idade precoce da coleta; a restrição de crescimento intrauterino isolada não é a explicação central para essa discordância; não há erro laboratorial sistemático descrito para coletas após 48 horas, sendo o problema justamente a coleta muito precoce.' },
  { id: 'ufpr_gerado26_077', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Menino de 18 meses, com anemia desde os 9 meses sem melhora com sulfato ferroso, aleitamento materno exclusivo até o 6.º mês, ingestão de carne apenas 2 vezes por semana. Hemograma com VCM reduzido, RDW aumentado, ferro sérico e ferritina reduzidos. O diagnóstico mais provável é:', options: ['anemia ferropriva.', 'talassemia minor.', 'aplasia pura da série vermelha.', 'deficiência de G6PD.', 'anemia de doença crônica.'], correctIndex: 0, explanation: 'VCM reduzido com RDW aumentado, ferro sérico e ferritina reduzidos, associados a baixa ingestão de ferro dietético, são compatíveis com anemia ferropriva. Talassemia minor cursaria com RDW tipicamente normal e ferritina normal ou aumentada; aplasia pura da série vermelha cursa com reticulocitopenia acentuada sem alteração dos índices de ferro; deficiência de G6PD causa hemólise episódica, não anemia ferropriva crônica; anemia de doença crônica cursa com ferritina normal ou elevada, diferente do achado descrito.' },
  { id: 'ufpr_gerado26_078', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Recém-nascido a termo, filho de mãe HIV positivo com carga viral indetectável e boa adesão à terapia antirretroviral, nasceu por parto vaginal. A conduta em relação à profilaxia neonatal é:', options: ['o recém-nascido deve receber profilaxia antirretroviral conforme risco estimado de transmissão, baseado nos dados maternos.', 'o recém-nascido não necessita de qualquer profilaxia, pois a carga viral indetectável exclui totalmente o risco.', 'o aleitamento materno deve ser mantido livremente, dado o bom controle materno da infecção.', 'a via de parto vaginal está sempre contraindicada em gestantes HIV positivo, independente da carga viral.', 'a profilaxia neonatal só é indicada se a mãe tiver iniciado a terapia antirretroviral após o parto.'], correctIndex: 0, explanation: 'Mesmo com carga viral materna indetectável, o recém-nascido deve receber profilaxia antirretroviral conforme o risco estimado de transmissão. Carga viral indetectável reduz mas não exclui totalmente o risco; o aleitamento materno é contraindicado em mães HIV positivo no Brasil; a via de parto pode ser vaginal em gestantes com carga viral controlada, não sendo contraindicação absoluta; a profilaxia neonatal é indicada mesmo quando a terapia materna foi iniciada e bem conduzida durante a gestação, não apenas se iniciada após o parto.' },
  { id: 'ufpr_gerado26_079', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Menina de 8 anos, com púrpura palpável em membros inferiores, dor abdominal em cólica e artralgia em joelhos, sem plaquetopenia. A principal hipótese diagnóstica e o órgão a ser monitorado a médio prazo são, respectivamente:', options: ['púrpura de Henoch-Schönlein (vasculite por IgA); rim, pelo risco de nefrite associada.', 'púrpura trombocitopênica imune; fígado, pelo risco de insuficiência hepática.', 'meningococcemia; pulmão, isoladamente.', 'dermatite atópica grave; coração, isoladamente.', 'leucemia aguda; baço, isoladamente.'], correctIndex: 0, explanation: 'Púrpura palpável associada a dor abdominal e artralgia, sem plaquetopenia, é típica da púrpura de Henoch-Schönlein, exigindo monitorização renal pelo risco de nefrite por IgA. A ausência de plaquetopenia afasta a púrpura trombocitopênica imune; meningococcemia cursaria com quadro toxêmico grave; dermatite atópica não explica a púrpura palpável nem a artralgia; leucemia aguda não é a hipótese mais compatível com esse quadro específico sem outras alterações hematológicas.' },
  { id: 'ufpr_gerado26_080', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Lactente de 5 meses, com cardiopatia congênita de hiperfluxo pulmonar (comunicação interventricular ampla), internado por bronquiolite viral aguda, evoluindo com desconforto respiratório progressivo. O fator de risco relevante para essa evolução mais grave é:', options: ['a cardiopatia congênita com hiperfluxo pulmonar, que aumenta o risco de evolução grave da bronquiolite.', 'a ausência completa de qualquer relação entre a cardiopatia e a gravidade da bronquiolite.', 'a contraindicação absoluta de oxigenoterapia suplementar nesse contexto.', 'a inexistência de qualquer relação fisiopatológica entre infecção respiratória e sobrecarga cardíaca.', 'o fato de a cardiopatia proteger contra formas graves de infecção respiratória viral.'], correctIndex: 0, explanation: 'Cardiopatias congênitas com hiperfluxo pulmonar são fator de risco reconhecido para evolução grave da bronquiolite viral aguda, pela sobrecarga circulatória pulmonar associada à infecção respiratória. Afirmar ausência de relação ignora essa associação bem estabelecida; a cardiopatia não contraindica oxigenoterapia, podendo ser ainda mais necessária; há sim relação fisiopatológica relevante entre infecção respiratória e sobrecarga cardíaca; a cardiopatia não protege contra formas graves, ao contrário, aumenta o risco de evolução desfavorável.' },
  { id: 'ufpr_gerado26_081', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Segundo o Guia Alimentar para Crianças Brasileiras Menores de 2 Anos, a alimentação complementar de um lactente de 6 meses em aleitamento materno deve:', options: ['priorizar alimentos in natura, evitando açúcares e ultraprocessados, mantendo o aleitamento materno junto às novas ofertas.', 'incluir sucos industrializados como substitutos da água entre as refeições.', 'incluir obrigatoriamente fórmula infantil, mesmo com produção adequada de leite materno.', 'manter consistência exclusivamente líquida até os 12 meses, independente da evolução da criança.', 'excluir completamente o aleitamento materno assim que iniciada a alimentação complementar.'], correctIndex: 0, explanation: 'O Guia Alimentar recomenda alimentos in natura, evitando açúcares e ultraprocessados, com manutenção do aleitamento materno junto à alimentação complementar. Sucos industrializados não substituem a água e devem ser evitados; fórmula infantil não é obrigatória havendo produção adequada de leite materno; a consistência deve evoluir progressivamente, não permanecer líquida até os 12 meses; o aleitamento materno deve ser mantido, não excluído, com a introdução da alimentação complementar.' },
  { id: 'ufpr_gerado26_082', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Menina de 10 meses, ao aplicar o instrumento de marcos de desenvolvimento da Caderneta da Criança, apresenta, pela primeira vez, ausência de resposta ao ser chamada pelo nome e falta de reação a sons ambientais. A conduta é:', options: ['encaminhar para avaliação audiológica, dada a importância do diagnóstico precoce de deficiência auditiva para o desenvolvimento da linguagem.', 'tranquilizar a família, pois a ausência de resposta a sons é esperada e normal nessa idade.', 'aguardar até os 3 anos de idade para qualquer avaliação da audição.', 'encaminhar diretamente para intervenção cirúrgica, sem qualquer avaliação audiológica prévia.', 'orientar apenas estimulação visual, sem qualquer investigação da função auditiva.'], correctIndex: 0, explanation: 'A ausência de resposta a sons e ao próprio nome é marco de alerta para deficiência auditiva, exigindo encaminhamento para avaliação audiológica precoce. Considerar normal ignora um achado de alerta relevante; aguardar até os 3 anos atrasa perigosamente uma intervenção que se beneficia de diagnóstico precoce; encaminhar direto para cirurgia sem avaliação prévia inverte a sequência correta de investigação; orientar apenas estimulação visual não investiga nem trata a possível deficiência auditiva.' },
  { id: 'ufpr_gerado26_083', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Menino de 4 anos, previamente hígido, apresenta febre de 38,5 a 39ºC e odinofagia há 2 dias, seguido de exantema micropapular áspero que poupa região perioral, língua em framboesa, e teste rápido positivo para estreptococo em orofaringe. O diagnóstico mais provável é:', options: ['escarlatina.', 'sarampo.', 'exantema súbito.', 'chikungunya.', 'varicela.'], correctIndex: 0, explanation: 'Febre, odinofagia, exantema micropapular áspero poupando região perioral, língua em framboesa e teste rápido positivo para estreptococo são achados clássicos da escarlatina. Sarampo cursa com exantema morbiliforme e manchas de Koplik, sem esse padrão; exantema súbito ocorre tipicamente em lactentes com febre alta seguida de exantema após defervescência; chikungunya cursa com artralgia intensa como achado central; varicela cursa com lesões vesiculares em diferentes estágios, não com esse exantema áspero micropapular.' },
  { id: 'ufpr_gerado26_084', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Adolescente de 14 anos, sexualmente ativa, procura consulta ginecológica sem os pais, com receio de que os responsáveis sejam informados. A conduta ética adequada é:', options: ['respeitar o sigilo e a autonomia da adolescente, informando-a sobre seus direitos, exceto em situações de risco grave previstas em lei.', 'comunicar imediatamente os pais antes de qualquer atendimento à adolescente.', 'recusar o atendimento até que a adolescente venha acompanhada de um responsável legal.', 'informar que o sigilo médico não se aplica a adolescentes em nenhuma circunstância.', 'atender normalmente, mas registrar o atendimento de forma acessível aos pais sem qualquer restrição.'], correctIndex: 0, explanation: 'Adolescentes têm direito ao sigilo e à autonomia crescente sobre sua saúde, devendo o atendimento respeitar esses direitos, com quebra de sigilo reservada a situações de risco grave previstas em lei. Comunicar os pais obrigatoriamente antes do atendimento pode afastar a adolescente do cuidado necessário; recusar o atendimento sem acompanhante prejudica a saúde da paciente; afirmar que o sigilo nunca se aplica a adolescentes contraria seus direitos reconhecidos; registrar de forma acessível aos pais sem restrição viola o direito ao sigilo da adolescente.' },
  { id: 'ufpr_gerado26_085', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Menino de 7 anos apresenta baixa estatura, dificuldade de aprendizagem e comportamento hiperativo. A mãe relata uso frequente de álcool durante toda a gestação. Ao exame físico, fendas palpebrais curtas, hipoplasia de face média e lábio superior fino. Em relação à quantidade segura de álcool na gestação, é correto afirmar que:', options: ['não existe quantidade segura definida para o uso de bebidas alcoólicas na gestação, recomendando-se abstinência absoluta.', 'o uso social de álcool é permitido no terceiro trimestre de gestação.', 'o álcool não atravessa a barreira hematoencefálica fetal, permitindo consumo moderado.', 'apenas o uso de destilados é prejudicial, sendo bebidas fermentadas seguras em qualquer quantidade.', 'o risco existe apenas se o consumo ocorrer exclusivamente no primeiro trimestre.'], correctIndex: 0, explanation: 'Não existe quantidade segura definida para o uso de álcool na gestação, sendo a recomendação de abstinência absoluta durante toda a gravidez. Permitir uso social no terceiro trimestre contraria essa recomendação; o álcool atravessa sim a barreira hematoencefálica fetal, sendo esse justamente o mecanismo de dano neurológico; não há diferenciação de segurança entre tipos de bebida alcoólica quanto ao risco fetal; o risco existe ao longo de toda a gestação, não exclusivamente no primeiro trimestre.' },
  { id: 'ufpr_gerado26_086', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Recém-nascido, filho de mãe diagnosticada com tuberculose pulmonar bacilífera, com tratamento iniciado 10 dias antes do parto. A conduta terapêutica adequada para o recém-nascido, considerando ausência de sintomas, é:', options: ['não vacinar com BCG inicialmente, iniciar profilaxia com isoniazida e reavaliar com PPD, mantendo a profilaxia conforme resultado.', 'vacinar com BCG e tratar com isoniazida por 3 meses, sem necessidade de realizar o PPD antes ou depois da profilaxia.', 'vacinar com BCG e fazer acompanhamento mensal, realizando PPD apenas se apresentar sintomatologia.', 'não dar vacina BCG, sem qualquer profilaxia com isoniazida, apenas acompanhamento clínico.', 'iniciar esquema completo de tratamento para tuberculose ativa no recém-nascido, independentemente de investigação.'], correctIndex: 0, explanation: 'O recém-nascido de mãe bacilífera não deve receber BCG inicialmente, devendo iniciar profilaxia com isoniazida e ser reavaliado com PPD, mantendo ou ajustando a profilaxia conforme o resultado. Vacinar com BCG e tratar com isoniazida sem realizar o PPD ignora essa etapa de reavaliação prevista no protocolo; vacinar e só realizar PPD diante de sintomas atrasa a investigação adequada; não dar BCG sem qualquer profilaxia deixa o recém-nascido exposto sem proteção; tratar como tuberculose ativa sem investigação prévia não é a conduta padronizada para o recém-nascido assintomático exposto.' },
  { id: 'ufpr_gerado26_087', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Menino de 5 anos, previamente hígido, com claudicação e dor na perna direita há 24 horas, sem febre, com quadro gripal autolimitado há 1 semana. Exame físico com posição antálgica do joelho e rotação externa do membro ipsilateral, sem outras alterações. A abordagem diagnóstico-terapêutica mais apropriada é:', options: ['ultrassonografia de quadril para avaliar sinovite transitória, com manejo sintomático e observação.', 'antibioticoterapia empírica de amplo espectro imediata, sem qualquer investigação de imagem prévia.', 'punção articular de urgência, independente da ausência de febre e sinais de toxemia.', 'ressonância magnética de coluna lombar como primeiro exame, sem avaliação do quadril.', 'cirurgia ortopédica de urgência, sem qualquer investigação por imagem.'], correctIndex: 0, explanation: 'Claudicação após quadro viral, sem febre ou toxemia, é compatível com sinovite transitória do quadril, investigada com ultrassonografia e manejada com sintomáticos e observação. Antibioticoterapia empírica imediata sem investigação é desproporcional na ausência de sinais de infecção; punção articular de urgência não é indicada sem sinais de toxemia sugestivos de artrite séptica; ressonância de coluna lombar não é o exame direcionado para esse quadro de quadril; cirurgia de urgência sem investigação prévia é inadequada para essa hipótese benigna e autolimitada.' },
  { id: 'ufpr_gerado26_088', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Lactente de 45 dias, com eliminação de fezes com raios de sangue em todas as evacuações há 15 dias, sem mudança na frequência ou consistência das fezes, em uso de fórmula láctea desde a segunda semana de vida, sem outros sintomas. O mecanismo fisiopatológico envolvido é:', options: ['reação não mediada por IgE, compatível com proctocolite alérgica induzida por proteína alimentar.', 'reação mediada por IgE, com risco de anafilaxia imediata.', 'deficiência primária de lactase, sem qualquer componente imunológico.', 'infecção bacteriana invasiva do trato intestinal, exigindo antibioticoterapia imediata.', 'doença inflamatória intestinal crônica já estabelecida nessa idade.'], correctIndex: 0, explanation: 'Sangue nas fezes sem outros sintomas sistêmicos, associado ao uso de fórmula láctea, é compatível com proctocolite alérgica induzida por proteína alimentar, mecanismo não mediado por IgE. Reação mediada por IgE cursaria com sintomas agudos como urticária, angioedema ou anafilaxia, ausentes no caso; deficiência de lactase causaria diarreia e distensão, não sangue nas fezes, e não seria de mecanismo imunológico; infecção bacteriana invasiva teria outros sinais sistêmicos associados; doença inflamatória intestinal crônica é extremamente rara nessa idade, sendo diagnóstico muito menos provável que a alergia alimentar.' },
  { id: 'ufpr_gerado26_089', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Recém-nascido de 28 semanas, peso de 1000g, com desconforto respiratório progressivo desde os primeiros minutos de vida, radiografia de tórax com infiltrado reticulogranular difuso. A conduta recomendada é:', options: ['suporte ventilatório (CPAP nasal ou ventilação mecânica conforme gravidade) e surfactante exógeno, se indicado.', 'antibioticoterapia isolada, sem qualquer suporte ventilatório.', 'observação isolada, sem qualquer intervenção respiratória, aguardando resolução espontânea.', 'apenas oxigênio em cateter nasal de baixo fluxo, independente da gravidade do desconforto.', 'ventilação mecânica invasiva obrigatória em todos os casos, sem considerar CPAP nasal.'], correctIndex: 0, explanation: 'O quadro é compatível com síndrome do desconforto respiratório do recém-nascido pré-termo por deficiência de surfactante, tratado com suporte ventilatório adequado à gravidade e surfactante exógeno quando indicado. Antibioticoterapia isolada não trata a causa primária dessa condição; observação isolada é perigosa diante de desconforto respiratório progressivo em prematuro extremo; oxigênio em baixo fluxo isolado pode ser insuficiente conforme a gravidade; ventilação mecânica invasiva obrigatória em todos os casos ignora a possibilidade de suporte não invasivo (CPAP) em casos menos graves.' },
  { id: 'ufpr_gerado26_090', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Recém-nascido, mãe com sorologias para toxoplasmose realizadas no início de cada trimestre gestacional com IgM e IgG não reagentes, apresenta teste do pezinho positivo para toxoplasmose com 10 dias de vida. A conduta é:', options: ['repetir a sorologia da mãe e do recém-nascido; se ambas positivas, tratar o recém-nascido conforme protocolo de toxoplasmose congênita.', 'considerar o teste do pezinho falso-positivo, pois as sorologias maternas na gestação foram negativas, sem qualquer nova avaliação.', 'tratar o recém-nascido empiricamente por 42 dias, sem necessidade de repetir qualquer sorologia.', 'repetir apenas o teste do pezinho, sem qualquer avaliação sorológica adicional da mãe ou do recém-nascido.', 'não repetir nenhum exame, aguardando o desenvolvimento de sintomas antes de qualquer conduta.'], correctIndex: 0, explanation: 'Diante de discordância entre sorologias maternas negativas na gestação e teste do pezinho positivo, deve-se repetir a sorologia da mãe e do recém-nascido para esclarecer o caso antes de definir o tratamento. Considerar automaticamente falso-positivo sem nova avaliação pode deixar passar uma infecção congênita real (por exemplo, se a infecção materna ocorreu tardiamente na gestação); tratar empiricamente por 42 dias sem qualquer confirmação sorológica adicional não segue o protocolo de investigação recomendado; repetir apenas o teste do pezinho, sem avaliar sorologicamente mãe e recém-nascido, é investigação incompleta; aguardar sintomas sem qualquer investigação atrasa perigosamente o diagnóstico e tratamento de uma possível infecção congênita.' },
  { id: 'ufpr_gerado26_091', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Reumatologia', text: 'Homem, 45 anos, com perda ponderal, mialgia, dor abdominal recorrente e neuropatia periférica, biópsia de nervo sural evidenciando inflamação transmural de artéria de médio calibre com necrose fibrinoide. O diagnóstico é:', options: ['poliarterite nodosa.', 'granulomatose com poliangeíte.', 'poliangeíte microscópica.', 'arterite de células gigantes.', 'crioglobulinemia mista essencial.'], correctIndex: 0, explanation: 'Inflamação transmural de artéria de médio calibre com necrose fibrinoide, associada a mononeurite múltipla e sintomas sistêmicos, é característica da poliarterite nodosa. A granulomatose com poliangeíte tipicamente acomete pequenos vasos com ANCA-c positivo e envolvimento respiratório/renal proeminente; a poliangeíte microscópica também acomete pequenos vasos, com ANCA-p mais frequente; a arterite de células gigantes acomete grandes vasos cranianos em idosos; a crioglobulinemia mista tem outro perfil sorológico e de acometimento vascular.' },
  { id: 'ufpr_gerado26_092', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Endocrinologia', text: 'Mulher, 55 anos, com fadiga, ganho de peso, constipação e intolerância ao frio, TSH elevado e anti-TPO positivo. O diagnóstico e o tratamento são:', options: ['tireoidite de Hashimoto; reposição de levotiroxina.', 'doença de Graves; tionamida antitireoidiana.', 'tireoidite subaguda; anti-inflamatório isolado.', 'bócio multinodular tóxico; iodo radioativo.', 'adenoma hipofisário produtor de TSH; cirurgia transesfenoidal imediata.'], correctIndex: 0, explanation: 'TSH elevado com anti-TPO positivo e sintomas de hipotireoidismo confirmam tireoidite de Hashimoto, tratada com reposição de levotiroxina. Doença de Graves e bócio multinodular tóxico cursam com hipertireoidismo (TSH baixo), quadro oposto; tireoidite subaguda cursa com dor cervical e disfunção transitória; adenoma hipofisário produtor de TSH é causa rara de hipertireoidismo central, com TSH inadequadamente normal ou elevado frente a hormônios tireoidianos altos, não compatível com o quadro de hipotireoidismo descrito.' },
  { id: 'ufpr_gerado26_093', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Urologia', text: 'Homem, 65 anos, com diminuição do jato urinário, noctúria, esvaziamento vesical incompleto há 6 meses, próstata aumentada e fibroelástica ao toque retal. A propedêutica e a terapêutica iniciais mais apropriadas são:', options: ['ultrassonografia de vias urinárias e PSA; alfabloqueador para alívio sintomático inicial.', 'apenas antibioticoterapia empírica, sem qualquer investigação complementar.', 'biópsia prostática imediata, independente do resultado do PSA e das características do toque retal.', 'apenas observação clínica, sem qualquer investigação ou tratamento.', 'cirurgia prostática de urgência, sem qualquer investigação prévia.'], correctIndex: 0, explanation: 'Sintomas obstrutivos urinários com próstata aumentada ao toque retal, sem características suspeitas de malignidade, são investigados com ultrassonografia e PSA, iniciando alfabloqueador para alívio sintomático da hiperplasia prostática benigna. Antibioticoterapia empírica isolada não trata a obstrução mecânica prostática; biópsia prostática imediata não é indicada sem critério de suspeição adequado (PSA alterado ou nódulo suspeito ao toque); observação isolada sem investigação ignora sintomas significativos há 6 meses; cirurgia de urgência sem investigação prévia é desproporcional para esse quadro não emergencial.' },
  { id: 'ufpr_gerado26_094', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Oncologia', text: 'Homem, 60 anos, com massa testicular indolor de crescimento progressivo, ultrassonografia confirmando lesão sólida intratesticular. A conduta é:', options: ['orquiectomia inguinal radical, com dosagem prévia de marcadores tumorais (alfa-fetoproteína, beta-hCG, LDH).', 'biópsia percutânea transescrotal da lesão como primeira etapa diagnóstica padrão.', 'observação clínica isolada por 6 meses, dado que a maioria das massas testiculares é benigna nessa faixa etária.', 'quimioterapia empírica isolada, sem qualquer avaliação cirúrgica ou dosagem de marcadores tumorais.', 'radioterapia local isolada, sem qualquer confirmação histológica prévia.'], correctIndex: 0, explanation: 'Massa testicular sólida sugestiva de neoplasia tem indicação de orquiectomia inguinal radical, com dosagem prévia de marcadores tumorais, evitando a biópsia transescrotal pelo risco de disseminação tumoral por essa via. A biópsia percutânea transescrotal não é a conduta padrão, pelo risco de contaminação da via linfática inguinal; observação isolada atrasa o diagnóstico e tratamento de uma provável neoplasia; quimioterapia e radioterapia empíricas sem diagnóstico histológico e estadiamento adequados não são condutas apropriadas nesse momento.' },
  { id: 'ufpr_gerado26_095', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Medicina Intensiva', text: 'Paciente, 55 anos, com choque séptico por foco urinário, hipotensão persistente (PA 75/45 mmHg) após 30 mL/kg de cristaloide em 3 horas, lactato ainda elevado. A conduta mais apropriada nesse momento é:', options: ['iniciar noradrenalina como vasopressor de primeira escolha, mantendo reavaliação volêmica.', 'infundir mais 30 mL/kg de cristaloide antes de considerar qualquer vasopressor, independente da resposta clínica.', 'iniciar dopamina em baixa dose como vasopressor de escolha inicial.', 'iniciar corticoide em altas doses como primeira medida, antes de qualquer vasopressor.', 'aguardar sem intervenção adicional até resultado de hemocultura, antes de considerar vasopressor.'], correctIndex: 0, explanation: 'Após reposição volêmica inicial sem resposta pressórica adequada no choque séptico, a noradrenalina é o vasopressor de primeira escolha, com reavaliação contínua da volemia. Infundir mais fluido indiscriminadamente sem reavaliar a resposta aumenta o risco de sobrecarga volêmica e edema pulmonar; dopamina em baixa dose não é a primeira escolha, associando-se a mais arritmias e sendo inferior à noradrenalina em desfechos; corticoide em altas doses não é a primeira medida, sendo reservado a choque refratário a vasopressor; aguardar hemocultura antes de intervir atrasa perigosamente o suporte hemodinâmico necessário.' },
  { id: 'ufpr_gerado26_096', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Dermatologia', text: 'Mulher, 50 anos, com bolhas flácidas que se rompem facilmente formando erosões dolorosas em pele e mucosa oral, sinal de Nikolsky positivo, biópsia com acantólise suprabasal. O diagnóstico e a base do tratamento são, respectivamente:', options: ['pênfigo vulgar; corticoterapia sistêmica em altas doses, associada a imunossupressores poupadores de corticoide.', 'penfigoide bolhoso; apenas corticoide tópico, sem terapia sistêmica.', 'dermatite herpetiforme; dieta isenta de glúten isolada, sem corticoide.', 'síndrome de Stevens-Johnson; suspensão de medicamento isolada, sem imunossupressão.', 'impetigo bolhoso; antibioticoterapia tópica isolada, sem corticoide.'], correctIndex: 0, explanation: 'Bolhas flácidas com acantólise suprabasal, sinal de Nikolsky positivo e acometimento de mucosa oral são característicos do pênfigo vulgar, tratado com corticoterapia sistêmica em altas doses associada a imunossupressores. O penfigoide bolhoso cursa com bolhas tensas e acometimento subepidérmico, geralmente poupando mucosas, tratado com corticoide sistêmico, não apenas tópico; a dermatite herpetiforme relaciona-se à doença celíaca, com lesões pruriginosas e não acantólise suprabasal; a síndrome de Stevens-Johnson relaciona-se a reação medicamentosa grave com necrólise epidérmica, não acantólise; o impetigo bolhoso é infecção bacteriana superficial, sem esse achado histológico de acantólise.' },
  { id: 'ufpr_gerado26_097', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Psiquiatria', text: 'Mulher, 28 anos, com episódios recorrentes e inesperados de taquicardia, sudorese, tremores, sensação de morte iminente e despersonalização, com duração de minutos, seguidos de medo persistente de novos episódios e evitação de sair sozinha de casa. O diagnóstico e o tratamento farmacológico de primeira linha são, respectivamente:', options: ['transtorno de pânico com agorafobia; inibidor seletivo da recaptação de serotonina.', 'transtorno de ansiedade generalizada; benzodiazepínico isolado como tratamento de manutenção contínua.', 'transtorno bipolar tipo I; lítio como monoterapia inicial isolada.', 'transtorno de estresse pós-traumático; antipsicótico típico isolado.', 'hipertireoidismo; apenas betabloqueador, sem qualquer abordagem psiquiátrica.'], correctIndex: 0, explanation: 'Crises recorrentes e inesperadas com sintomas autonômicos intensos, medo de novas crises e evitação comportamental caracterizam transtorno de pânico com agorafobia, tratado em primeira linha com ISRS. Transtorno de ansiedade generalizada cursa com preocupação excessiva persistente, não crises episódicas abruptas, e benzodiazepínico isolado contínuo não é a primeira linha pelo risco de dependência; transtorno bipolar cursaria com episódios de humor, não esse padrão de crises autonômicas; TEPT exige exposição a evento traumático definido, não mencionado no caso, e antipsicótico típico não é primeira linha; hipertireoidismo deve ser excluído na investigação, mas o quadro comportamental completo (evitação, medo antecipatório) aponta para transtorno de pânico, não sendo tratado apenas com betabloqueador.' },
  { id: 'ufpr_gerado26_098', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Nefrologia', text: 'Homem, 62 anos, em hemodiálise crônica, apresenta no eletrocardiograma de rotina pré-diálise ondas T apiculadas e alargamento do complexo QRS, potássio sérico de 7,2 mEq/L. A conduta imediata prioritária é:', options: ['gluconato de cálcio intravenoso para estabilização da membrana miocárdica, seguido de medidas para redução do potássio sérico.', 'apenas aumentar a dose de resina de troca iônica oral, sem qualquer medida imediata.', 'aguardar a próxima sessão de diálise agendada, sem qualquer intervenção imediata.', 'reposição de potássio oral, para investigar se o quadro é de pseudo-hipercalemia.', 'apenas hidratação venosa isolada, sem qualquer outra medida.'], correctIndex: 0, explanation: 'Hipercalemia grave com alterações eletrocardiográficas exige gluconato de cálcio intravenoso imediato para estabilizar a membrana miocárdica e reduzir o risco de arritmia fatal, seguido de medidas para reduzir o potássio sérico. Aumentar apenas a resina oral tem início de ação lento, insuficiente diante de alterações eletrocardiográficas já presentes; aguardar a próxima diálise agendada é perigoso diante de hipercalemia sintomática ao ECG; repor potássio pioraria ainda mais o quadro; hidratação venosa isolada não trata a hipercalemia grave nem estabiliza a membrana miocárdica.' },
  { id: 'ufpr_gerado26_099', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pneumologia', text: 'Mulher, 45 anos, pós-operatório de cirurgia ortopédica há 5 dias, em repouso prolongado no leito, apresenta dispneia súbita, taquicardia e dor torácica pleurítica, com escore de Wells indicando probabilidade alta de tromboembolismo pulmonar. A conduta mais apropriada é:', options: ['iniciar anticoagulação empírica e prosseguir a investigação de imagem (angiotomografia de tórax) para confirmação diagnóstica.', 'aguardar o resultado da angiotomografia de tórax antes de iniciar qualquer anticoagulação, independente da probabilidade clínica.', 'solicitar apenas radiografia de tórax como exame definitivo, sem angiotomografia.', 'iniciar trombolítico sistêmico imediato, independente de sinais de instabilidade hemodinâmica.', 'solicitar apenas D-dímero como exame confirmatório definitivo, sem exame de imagem.'], correctIndex: 0, explanation: 'Em paciente com alta probabilidade clínica de tromboembolismo pulmonar (Wells alto), a anticoagulação empírica deve ser iniciada enquanto se prossegue a investigação por imagem, dado o risco de deterioração à espera da confirmação. Aguardar a angiotomografia sem anticoagulação empírica expõe a paciente a risco de progressão do tromboembolismo; radiografia de tórax não é exame definitivo para tromboembolismo pulmonar; trombolítico sistêmico é reservado a casos com instabilidade hemodinâmica (TEP maciço), não indicado de rotina; D-dímero tem alto valor preditivo negativo em baixa probabilidade clínica, mas não é exame confirmatório e não deve substituir a imagem em alta probabilidade clínica.' },
  { id: 'ufpr_gerado26_100', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Vascular', text: 'Homem, 55 anos, tabagista, com claudicação intermitente progressiva em membro inferior direito, pulsos femorais diminuídos e ausência de pulsos distais, índice tornozelo-braquial reduzido. A conduta inicial mais apropriada é:', options: ['cessação do tabagismo, exercício físico supervisionado e terapia medicamentosa otimizada, reservando revascularização para casos refratários ou isquemia crítica.', 'amputação primária do membro, independente da gravidade e da resposta a tratamento conservador.', 'anticoagulação plena isolada, sem qualquer outra intervenção sobre os fatores de risco.', 'revascularização cirúrgica de urgência em todos os casos de claudicação intermitente, independente da gravidade.', 'apenas repouso absoluto, sem qualquer orientação de exercício físico.'], correctIndex: 0, explanation: 'A doença arterial obstrutiva periférica com claudicação é inicialmente tratada com cessação do tabagismo, exercício físico supervisionado e terapia medicamentosa otimizada, reservando revascularização para casos refratários ou isquemia crítica. Amputação primária é medida de exceção para casos com isquemia irreversível, não a conduta inicial; anticoagulação plena isolada não é o tratamento padrão para claudicação por doença aterosclerótica; revascularização de urgência não é indicada para toda claudicação, sendo reservada a casos selecionados; repouso absoluto sem exercício contraria a recomendação atual, que prioriza exercício supervisionado como parte do tratamento.' },
];
